import React, { useEffect, useState } from 'react';

interface FieryTransitionProps {
  isActive: boolean;
  onComplete: () => void;
}

export const FieryTransition: React.FC<FieryTransitionProps> = ({ isActive, onComplete }) => {
  const [shouldRender, setShouldRender] = useState(false);

  useEffect(() => {
    if (isActive) {
      setShouldRender(true);
    }
  }, [isActive]);

  const handleAnimationEnd = () => {
    onComplete();
    // After animation, we can unmount the component
    setShouldRender(false);
  };

  if (!shouldRender) {
    return null;
  }

  return (
    <>
      <style>{`
        @keyframes fire-wipe {
          0% { transform: translateY(100%); }
          50% { transform: translateY(0%); }
          100% { transform: translateY(-100%); }
        }
        @keyframes fire-flicker-transition {
          0% { transform: scale(1) skewX(0); opacity: 0.8; }
          25% { transform: scale(1.1) skewX(5deg); opacity: 1; }
          50% { transform: scale(0.9) skewX(-5deg); opacity: 0.9; }
          75% { transform: scale(1.05) skewX(2deg); opacity: 1; }
          100% { transform: scale(1) skewX(0); opacity: 0.8; }
        }
        .fire-transition-overlay {
          position: fixed;
          inset: 0;
          z-index: 99999;
          pointer-events: none;
          background: transparent;
          overflow: hidden;
          animation: fire-wipe 1.2s cubic-bezier(0.6, 0.04, 0.98, 0.335) forwards;
        }
        .fire-transition-particle-container {
            position: absolute;
            inset: 0;
            filter: blur(8px) contrast(2);
        }
        .fire-transition-particle {
            position: absolute;
            bottom: -50px;
            width: 10vw;
            height: 20vh;
            background: radial-gradient(circle, #fef08a 0%, #f97316 40%, #dc2626 70%, transparent 80%);
            border-radius: 50%;
            animation-name: fire-flicker-transition;
            animation-iteration-count: infinite;
        }
      `}</style>
      <div 
        className="fire-transition-overlay"
        onAnimationEnd={handleAnimationEnd}
      >
        <div className="fire-transition-particle-container">
          {Array.from({ length: 15 }).map((_, i) => (
            <div
              key={i}
              className="fire-transition-particle"
              style={{
                left: `${Math.random() * 100}vw`,
                animationDuration: `${Math.random() * 0.5 + 0.3}s`,
                animationDelay: `${Math.random() * 0.2}s`,
                transform: `scale(${Math.random() * 0.5 + 0.8})`,
              }}
            />
          ))}
        </div>
      </div>
    </>
  );
};

import { decode, decodeAudioData } from '../utils/audioUtils';

// Define the base URL for the backend API
const API_BASE_URL = 'http://localhost:8080';

/**
 * Fetches the API key from the backend. This is used for client-side,
 * web-only Gemini APIs like the Live API.
 * @returns A promise that resolves to the API key string.
 */
export const getApiKey = async (): Promise<string> => {
    try {
        const response = await fetch(`${API_BASE_URL}/api/key`);
        if (!response.ok) {
            const errorData = await response.json();
            throw new Error(errorData.error || "Failed to fetch API key from server.");
        }
        const data = await response.json();
        if (!data.apiKey) {
            throw new Error("API key not found in server response.");
        }
        return data.apiKey;
    } catch (error) {
        console.error("Error fetching API key:", error);
        throw error;
    }
};


/**
 * Sends text to the backend server to generate speech.
 * This function calls the `/api/speech` endpoint, which securely handles the
 * call to the Gemini TTS model.
 * @param text The text to be converted to speech.
 * @param audioContext The browser's AudioContext for decoding.
 * @param voice The desired voice for the speech synthesis.
 * @returns A promise that resolves to a playable AudioBuffer.
 */
export const generateSpeech = async (text: string, audioContext: AudioContext, voice: string): Promise<AudioBuffer> => {
    try {
        const trimmedText = text.trim();
        if (!trimmedText) {
            throw new Error("No text provided to generate speech.");
        }

        const response = await fetch(`${API_BASE_URL}/api/speech`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ text: trimmedText, voice }),
        });

        if (!response.ok) {
            const errorData = await response.json();
            throw new Error(errorData.error || "Failed to generate speech on server.");
        }

        const data = await response.json();
        const base64Audio = data.audioContent;
        if (!base64Audio) {
            throw new Error("No audio data received from server.");
        }

        const decodedBytes = decode(base64Audio);
        return await decodeAudioData(decodedBytes, audioContext, 24000, 1);

    } catch (error) {
        console.error("Error generating speech via backend:", error);
        if (error instanceof TypeError && error.message.includes('Failed to fetch')) {
             throw new Error("Could not connect to the backend server for speech generation. Is it running on http://localhost:8080?");
        }
        throw error;
    }
};

/**
 * Sends text to the backend server to classify its intent.
 * This function calls the `/api/classify` endpoint, which uses a Gemini model
 * to determine if the text is sexual, violent, emotional, or neutral.
 * @param text The text to classify.
 * @returns A promise that resolves to the classification string (e.g., 'sexual').
 */
export const classifyTextIntent = async (text: string): Promise<string> => {
    if (!text.trim()) return 'neutral';

    try {
        const response = await fetch(`${API_BASE_URL}/api/classify`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ text }),
        });

        if (!response.ok) {
            console.error("Server error during text classification.");
            return 'neutral';
        }

        const data = await response.json();
        return data.classification || 'neutral';

    } catch (error) {
        console.error("Error classifying text intent via backend:", error);
        return 'neutral'; // Default to neutral on API error
    }
};

/*
================================================================================
IMPORTANT NOTE FOR PRODUCTION DEPLOYMENT
================================================================================
The Gemini Live API (`ai.live.connect`) is a web-only feature that establishes a
direct WebSocket connection from the client to Google's servers. The Node.js
`@google/genai` SDK does not support this Live API.

Therefore, this component CANNOT be proxied through our Node.js backend using
the existing SDK. For a truly secure production environment where the API key is
never exposed to the client, a dedicated, low-latency WebSocket proxy service
would need to be built. This is a complex task beyond the scope of this
component's current architecture.

As a temporary measure for functionality, this component initializes the Gemini
API directly on the client. In a production build, `process.env.API_KEY` will
be undefined. This component will fail unless a key is provided through another
mechanism.

TODO: For production, replace the client-side API key with a secure token
generation and validation system.
================================================================================
*/
import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, Blob } from "@google/genai";
import { MicMuteIcon } from './MicMuteIcon';
import { PhoneHangUpIcon } from './PhoneHangUpIcon';
import type { Message } from '../types';
import { Sender } from '../types';
import { encode, decode, decodeAudioData } from '../utils/audioUtils';
import { VoiceVisualizer } from './VoiceVisualizer';
import { ListeningLoader } from './ListeningLoader';
import { getApiKey } from '../services/geminiService';

interface LiveVoiceModeOverlayProps {
    onClose: () => void;
    onAddLiveMessages: (messages: Message[]) => void;
    systemInstruction: string;
}

type Status = 'connecting' | 'listening' | 'thinking' | 'speaking' | 'error';
type TranscriptionEntry = { sender: 'user' | 'ai'; text: string };

const BurnInAnimation: React.FC = () => (
    <div className="burn-in-animation">
        <div className="content">
            <div className="burn">
                <div className="flame"></div> <div className="flame"></div>
                <div className="flame"></div> <div className="flame"></div>
                <div className="flame"></div> <div className="flame"></div>
                <div className="flame"></div> <div className="flame"></div>
                <div className="flame"></div> <div className="flame"></div>
            </div>
        </div>
    </div>
);

export const LiveVoiceModeOverlay: React.FC<LiveVoiceModeOverlayProps> = ({ onClose, onAddLiveMessages, systemInstruction }) => {
    const [status, setStatus] = useState<Status>('connecting');
    const [isMuted, setIsMuted] = useState(false);
    const [showBurnIn, setShowBurnIn] = useState(true);
    const [analyserNode, setAnalyserNode] = useState<AnalyserNode | null>(null);
    const [transcriptionHistory, setTranscriptionHistory] = useState<TranscriptionEntry[]>([]);
    const [currentInterimTranscript, setCurrentInterimTranscript] = useState('');
    const [errorMessage, setErrorMessage] = useState('');

    const transcriptEndRef = useRef<HTMLDivElement>(null);
    const sessionRef = useRef<{ close: () => void; sendRealtimeInput: (input: { media: Blob }) => void } | null>(null);
    const inputAudioContextRef = useRef<AudioContext | null>(null);
    const outputAudioContextRef = useRef<AudioContext | null>(null);
    const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
    const mediaStreamSourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
    const mediaStreamRef = useRef<MediaStream | null>(null);
    const isMutedRef = useRef(isMuted);

    const outputSources = useRef(new Set<AudioBufferSourceNode>());
    const nextStartTime = useRef(0);

    const userInputTranscript = useRef('');
    const aiOutputTranscript = useRef('');
    const thinkingTimerRef = useRef<number | null>(null);

    useEffect(() => {
        isMutedRef.current = isMuted;
    }, [isMuted]);

    const handleToggleMute = () => {
        setIsMuted(prev => !prev);
    };

    useEffect(() => {
        const timer = setTimeout(() => setShowBurnIn(false), 4000);
        return () => clearTimeout(timer);
    }, []);

    useEffect(() => {
        transcriptEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [transcriptionHistory, currentInterimTranscript]);

    const cleanup = useCallback(() => {
        if (thinkingTimerRef.current) clearTimeout(thinkingTimerRef.current);
        sessionRef.current?.close();
        sessionRef.current = null;
        mediaStreamRef.current?.getTracks().forEach(track => track.stop());
        scriptProcessorRef.current?.disconnect();
        mediaStreamSourceRef.current?.disconnect();
        if (inputAudioContextRef.current?.state !== 'closed') inputAudioContextRef.current?.close();
        if (outputAudioContextRef.current?.state !== 'closed') outputAudioContextRef.current?.close();
        outputSources.current.forEach(source => source.stop());
        outputSources.current.clear();
    }, []);

    const handleEndSession = useCallback(() => {
        cleanup();
        onClose();
    }, [cleanup, onClose]);

    useEffect(() => {
        const connectAndListen = async () => {
            try {
                const apiKey = await getApiKey();
                if (!apiKey) {
                    throw new Error("Live voice mode is not configured. Could not retrieve API key from server.");
                }

                const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
                mediaStreamRef.current = stream;

                const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
                inputAudioContextRef.current = inputCtx;
                outputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

                const ai = new GoogleGenAI({ apiKey });

                const sessionPromise = ai.live.connect({
                    model: 'gemini-2.5-flash-native-audio-preview-09-2025',
                    config: {
                        systemInstruction,
                        responseModalities: [Modality.AUDIO],
                        inputAudioTranscription: {},
                        outputAudioTranscription: {},
                        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Fenrir' } } }
                    },
                    callbacks: {
                        onopen: () => {
                            if (!mediaStreamRef.current || !inputCtx) return;

                            const source = inputCtx.createMediaStreamSource(mediaStreamRef.current);
                            mediaStreamSourceRef.current = source;

                            const analyser = inputCtx.createAnalyser();
                            setAnalyserNode(analyser);

                            const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
                            scriptProcessorRef.current = scriptProcessor;

                            source.connect(analyser);
                            analyser.connect(scriptProcessor);
                            scriptProcessor.connect(inputCtx.destination);

                            scriptProcessor.onaudioprocess = (e) => {
                                if (status !== 'speaking') setStatus('listening');

                                if (thinkingTimerRef.current) clearTimeout(thinkingTimerRef.current);
                                thinkingTimerRef.current = window.setTimeout(() => setStatus('thinking'), 1200);

                                if (isMutedRef.current) return; 

                                const inputData = e.inputBuffer.getChannelData(0);
                                const pcmBlob: Blob = {
                                    data: encode(new Uint8Array(new Int16Array(inputData.map(v => v * 32768)).buffer)),
                                    mimeType: 'audio/pcm;rate=16000',
                                };
                                sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
                            };
                        },
                        onmessage: async (message: LiveServerMessage) => {
                            if (thinkingTimerRef.current) clearTimeout(thinkingTimerRef.current);

                            if (message.serverContent?.inputTranscription) {
                                userInputTranscript.current += message.serverContent.inputTranscription.text;
                                setCurrentInterimTranscript(userInputTranscript.current);
                            }
                            if (message.serverContent?.outputTranscription) {
                                aiOutputTranscript.current += message.serverContent.outputTranscription.text;
                            }

                            const audioPart = message.serverContent?.modelTurn?.parts?.find(p => p.inlineData);
                            if (audioPart?.inlineData?.data && outputAudioContextRef.current) {
                                setStatus('speaking');
                                const audioBuffer = await decodeAudioData(decode(audioPart.inlineData.data), outputAudioContextRef.current, 24000, 1);
                                const source = outputAudioContextRef.current.createBufferSource();
                                source.buffer = audioBuffer;
                                source.connect(outputAudioContextRef.current.destination);

                                const startTime = Math.max(outputAudioContextRef.current.currentTime, nextStartTime.current);
                                source.start(startTime);
                                nextStartTime.current = startTime + audioBuffer.duration;
                                outputSources.current.add(source);
                                source.onended = () => {
                                    outputSources.current.delete(source);
                                    if(outputSources.current.size === 0) setStatus('listening');
                                };
                            }

                            if (message.serverContent?.turnComplete) {
                                const userText = userInputTranscript.current.trim();
                                const aiText = aiOutputTranscript.current.trim();
                                const newEntries: TranscriptionEntry[] = [];
                                if (userText) newEntries.push({ sender: 'user', text: userText });
                                if (aiText) newEntries.push({ sender: 'ai', text: aiText });
                                if (newEntries.length > 0) setTranscriptionHistory(prev => [...prev, ...newEntries]);

                                userInputTranscript.current = '';
                                aiOutputTranscript.current = '';
                                setCurrentInterimTranscript('');
                            }
                        },
                        onerror: (e: ErrorEvent) => {
                            console.error('Live session error:', e.message);
                            setErrorMessage('A network error occurred. The connection was lost.');
                            setStatus('error');
                        },
                        onclose: () => console.log('Live session closed.'),
                    }
                });
                sessionRef.current = await sessionPromise;
            } catch (err: any) {
                console.error("Error setting up live voice mode:", err);
                setErrorMessage(err.message || "Could not start live voice mode. Please check microphone permissions.");
                setStatus('error');
            }
        };

        connectAndListen();
        return () => cleanup();
    }, [systemInstruction, onAddLiveMessages, cleanup]);

    const getStatusText = () => {
        if (isMuted) return 'Muted';
        switch (status) {
            case 'connecting': return 'hmm....';
            case 'listening': return 'Listening...';
            case 'thinking': return 'Thinking...';
            case 'speaking': return 'Speaking...';
            case 'error': return errorMessage || 'Connection lost.';
            default: return '';
        }
    };

    const MainUI = () => (
        <>
            <div className="live-voice-header">
                <button onClick={handleEndSession} className="p-2 text-white/70 hover:text-white btn-radiate-glow" aria-label="Exit Live Mode">
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
            </div>

            <div className="flex-1 flex flex-col items-center justify-start text-center w-full pt-16">
                 {status === 'listening' && !isMuted && <ListeningLoader />}
                 <p className={`text-2xl font-medium min-h-[2rem] ${status === 'error' ? 'text-red-400' : 'text-white'}`}>{getStatusText()}</p>
                 <div ref={transcriptEndRef} className="live-voice-transcript w-full max-w-2xl no-scrollbar smooth-scroll fade-scroll-edges">
                     {transcriptionHistory.map((entry, i) => (
                        <p key={i} className={`text-lg ${entry.sender === 'user' ? 'text-white/90' : 'bg-gradient-to-r from-orange-500 to-red-600 bg-clip-text text-transparent font-semibold'}`}>
                           {entry.text}
                        </p>
                     ))}
                     {currentInterimTranscript && <p className="text-lg text-white/60">{currentInterimTranscript}</p>}
                 </div>
            </div>

            <div className="absolute bottom-12 left-0 right-0 h-48 pointer-events-none">
                <VoiceVisualizer isListening={!isMuted} analyserNode={analyserNode} />
            </div>

            <div className="live-voice-footer left-1/2 -translate-x-1/2">
                <button onClick={handleToggleMute} className={`mute-btn p-5 rounded-full transition-colors btn-radiate-glow ${isMuted ? 'muted' : ''}`} aria-label={isMuted ? "Unmute" : "Mute"}>
                    <div className="text-white">
                        <MicMuteIcon />
                    </div>
                </button>
                <button onClick={handleEndSession} className="end-call-btn p-5 rounded-full btn-radiate-glow" aria-label="End Call">
                    <PhoneHangUpIcon />
                </button>
            </div>
        </>
    );

    return (
        <div className="fixed inset-0 bg-black/90 backdrop-blur-2xl z-50 flex flex-col items-center justify-center p-4 animate-fade-in">
            {showBurnIn ? (
                <div className="flex flex-col items-center">
                    <div className="w-[350px] h-[350px]"><BurnInAnimation /></div>
                    <div className="themed-dot-loader flex space-x-2 mt-8">
                        <div className="h-3 w-3 animate-dot-bounce rounded-full dot-1"></div>
                        <div className="h-3 w-3 animate-dot-bounce rounded-full dot-2"></div>
                        <div className="h-3 w-3 animate-dot-bounce rounded-full dot-3"></div>
                    </div>
                </div>
            ) : <MainUI />}
        </div>
    );
};

import express from 'express';
import cors from 'cors';
import bodyParser from 'body-parser';
import { GoogleGenAI, Modality } from "@google/genai";
import 'dotenv/config';
import { modeDirectives, initialSystemInstruction } from './persona';

const app = express();
const port = process.env.PORT || 8080;

// --- Middleware Setup ---
app.use(cors()); 
app.use(bodyParser.json({ limit: '10mb' })); 

// --- Gemini API Initialization ---
let ai: GoogleGenAI | null = null;
if (!process.env.API_KEY) {
    console.error("FATAL ERROR: API_KEY environment variable is not set.");
    console.error("The server will run, but all Gemini API calls will fail.");
    console.error("Please create a .env file in the /server directory with your API_KEY.");
} else {
    ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
}

// --- Helper to check for API Key ---
const checkApiKey = (res: express.Response): boolean => {
    if (!ai) {
        res.status(500).json({ error: "Server is not configured with a valid API_KEY. See server logs for details." });
        return false;
    }
    return true;
};

// --- API Endpoints ---

/**
 * Endpoint for handling chat messages.
 */
app.post('/api/chat', async (req, res) => {
    if (!checkApiKey(res)) return;

    const { message, mode, history, user, model, attachments, useWebSearch, quotedMessage } = req.body;

    if (!model) {
        return res.status(400).json({ error: "AI model must be specified." });
    }

    try {
        let effectiveMode = mode;
        if (user?.isSpecialUser && mode === 'Fuck It') {
            effectiveMode = 'Fuck It (Seductive)';
        }
        const modeDirective = modeDirectives[effectiveMode as keyof typeof modeDirectives] || modeDirectives['Real Talk'];

        const finalSystemInstruction = `
            ${initialSystemInstruction}
            // --- CURRENT MODE DIRECTIVE: ${mode} ---
            ${modeDirective}
        `;

        const formattedHistory = history || [];

        const finalMessage = quotedMessage 
            ? `In response to the user saying "${quotedMessage.text}", the user has now said: "${message}"`
            : message;

        const messageParts: any[] = [];
        if (finalMessage?.trim()) {
          messageParts.push({ text: finalMessage });
        }
        if (attachments && attachments.length > 0) {
            attachments.forEach((att: { mimeType: string; base64: string }) => {
                messageParts.push({
                    inlineData: {
                        mimeType: att.mimeType,
                        data: att.base64,
                    }
                });
            });
        }

        const contents = [...formattedHistory, { role: 'user', parts: messageParts }];

        const config: any = {
            systemInstruction: finalSystemInstruction,
        };

        if (useWebSearch) {
            config.tools = [{ googleSearch: {} }];
        }

        if (['Deep Dive', 'Mentor Mode'].includes(mode)) {
            config.thinkingConfig = {
                thinkingBudget: model === 'gemini-2.5-pro' ? 8192 : 4096,
            };
        }

        const response = await ai!.models.generateContent({
            model,
            contents,
            config,
        });

        res.json({ 
            text: response.text,
            groundingMetadata: response.candidates?.[0]?.groundingMetadata,
        });
    } catch (error: any) {
        console.error("Error in /api/chat:", error);
        res.status(500).json({ error: "Damn, my connection to the ether is a bit fuzzy right now. The model might have flagged the request or an internal error occurred." });
    }
});

/**
 * Endpoint for generating speech from text.
 */
app.post('/api/speech', async (req, res) => {
    if (!checkApiKey(res)) return;

    const { text, voice } = req.body;
    try {
        const trimmedText = text ? text.trim() : '';
        if (!trimmedText) {
            return res.status(400).json({ error: "No text provided to generate speech." });
        }

        const response = await ai!.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text: trimmedText }] }],
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: voice || 'Puck' } },
                },
            },
        });

        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (!base64Audio) {
            throw new Error("No audio data received from API.");
        }
        res.json({ audioContent: base64Audio });
    } catch (error) {
        console.error("Error in /api/speech:", error);
        res.status(500).json({ error: "Failed to generate speech." });
    }
});

/**
 * Endpoint for classifying the intent of a given text.
 */
app.post('/api/classify', async (req, res) => {
    if (!checkApiKey(res)) return;

    const { text } = req.body;
    if (!text || !text.trim()) {
        return res.json({ classification: 'neutral' });
    }

    const prompt = `
      Analyze the user's text and classify its primary intent into one of these single-word categories: sexual, violent, emotional, neutral.
      Your analysis should be nuanced. "Sexual" refers to explicit descriptions, strong innuendo, role-playing, or clear romantic/flirtatious advances. It's not just about mentioning body parts.

      --- EXAMPLES ---
      User Text: "I want to feel you inside me."
      Classification: sexual
      User Text: "That movie was so sad, I cried for an hour."
      Classification: emotional
      User Text: "What's the weather like today?"
      Classification: neutral
      User Text: "I'm so angry I could punch a wall."
      Classification: violent
      --- END EXAMPLES ---

      Now, classify the following user text. Respond with only the single-word category.

      User Text: "${text}"
      Classification:
    `;

    try {
        const response = await ai!.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: prompt,
        });
        const classification = response.text.trim().toLowerCase();

        if (['sexual', 'violent', 'emotional', 'neutral'].includes(classification)) {
            res.json({ classification });
        } else {
            console.warn(`Unexpected classification from model: "${classification}"`);
            res.json({ classification: 'neutral' });
        }
    } catch (error) {
        console.error("Error in /api/classify:", error);
        res.status(500).json({ error: "Failed to classify text." });
    }
});

/**
 * Endpoint to securely provide the API key to the client for web-only APIs.
 * In a production environment, this should be replaced with a more secure
 * token-based authentication system.
 */
app.get('/api/key', (req, res) => {
    if (!process.env.API_KEY) {
        return res.status(500).json({ error: "API_KEY is not configured on the server." });
    }
    res.json({ apiKey: process.env.API_KEY });
});

// --- Server Startup ---
app.listen(port, () => {
    console.log(`Daren Nexus server is running on port ${port}`);
});

import React from 'react';

export const VaultIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={1.5}>
        <path strokeLinecap="round" strokeLinejoin="round" d="M8 11V7a4 4 0 118 0v4M5 9h14l1 12H4L5 9z" />
    </svg>
);

import React, { useState, useEffect } from 'react';
import { User, Memory } from '../types';
import { getMemoriesForUser } from '../services/memoryService';
import { CloseIcon } from './CloseIcon';
import { AppIconDarkGrey } from './AppIconDarkGrey';

interface MemoryVaultModalProps {
  isOpen: boolean;
  onClose: () => void;
  currentUser: User;
}

const MemoryCard: React.FC<{ memory: Memory }> = ({ memory }) => (
    <div className="bg-white/5 p-4 rounded-lg flex items-start gap-4 border border-white/10">
        <div className="w-8 h-8 flex-shrink-0 opacity-20 mt-1">
            <AppIconDarkGrey />
        </div>
        <p className="text-slate-300 text-base">{memory.preview}</p>
    </div>
);

export const MemoryVaultModal: React.FC<MemoryVaultModalProps> = ({ isOpen, onClose, currentUser }) => {
    const [memories, setMemories] = useState<Memory[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        if (isOpen && currentUser) {
            setIsLoading(true);
            getMemoriesForUser(currentUser.hash)
                .then(setMemories)
                .finally(() => setIsLoading(false));
        }
    }, [isOpen, currentUser]);

    if (!isOpen) return null;

    const renderContent = () => {
        if (isLoading) {
            return (
                <div className="text-center text-slate-400 py-8">
                    <p className="font-bold text-lg">ACCESSING MEMORY CORE...</p>
                </div>
            );
        }

        if (memories.length > 0) {
            return memories.map(memory => <MemoryCard key={memory.id} memory={memory} />);
        }

        return (
            <div className="text-center text-slate-400 py-8">
                <p className="font-bold text-lg">MEMORY VAULT IS EMPTY.</p>
                <p className="text-base mt-1">NO CORE MEMORIES FOUND.</p>
            </div>
        );
    };

    return (
        <div className="modal-overlay animate-fade-in" onClick={onClose}>
            <div className="bg-[var(--modal-bg)] border border-[var(--ui-border-color)] rounded-2xl shadow-2xl max-w-md w-full max-h-[90vh] flex flex-col overflow-hidden transition-colors duration-500" onClick={(e) => e.stopPropagation()}>
                <div className="p-6 pb-4">
                    <div className="flex items-center justify-between">
                        <h2 className="font-heading text-xl text-white">Memory Vault</h2>
                        <button 
                            onClick={onClose}
                            className="p-2 rounded-full hover:bg-white/10 transition-colors btn-radiate-glow"
                            aria-label="Close memory vault"
                        >
                            <CloseIcon />
                        </button>
                    </div>
                </div>
                <div className="flex-1 overflow-y-auto px-6 pb-6 space-y-3 smooth-scroll">
                    {renderContent()}
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { AuthScreen } from './components/AuthScreen';
import { ChatHistory } from './components/ChatHistory';
import { ChatWindow } from './components/ChatWindow';
import { Header } from './components/Header';
import { Home } from './components/Home';
import { InitialLoading } from './components/InitialLoading';
import { Intro } from './components/Intro';
import { Menu } from './components/Menu';
import { MessageInput } from './components/MessageInput';
import { AppearanceModal } from './components/AppearanceModal';
import { VoiceSelectionModal } from './components/VoiceSelectionModal';
import { ModeSelectionModal } from './components/ModeSelectionModal';
import { BugReportModal } from './components/BugReportModal';
import { VoiceInputOverlay } from './components/VoiceInputOverlay';
import { AgeGatingModal } from './components/AgeGatingModal';
import { LiveVoiceModeOverlay } from './components/LiveVoiceModeOverlay';
import { NexusAndChillModal } from './components/NexusAndChillModal';
import { ForgotPasswordModal } from './components/ForgotPasswordModal';
import { ProfileModal } from './components/ProfileModal';
import { MemoryVaultModal } from './components/MemoryVaultModal';

import { loginOrSignup, continueAsGuest, getCurrentUser, logout, saveCurrentUserName } from './services/authService';
import { archiveCurrentSession } from './services/chatHistoryService';
import { sendMessage } from './services/dialogflowService';
import { generateSpeech, classifyTextIntent } from './services/geminiService';
import {
  getCurrentSession,
  getLiveSystemInstruction,
  getTtsVoice,
  getTextZoom,
  getTheme,
  saveCurrentSession,
  saveTtsVoice,
  saveTextZoom,
  saveTheme,
} from './services/persistenceService';
import { initialSystemInstruction } from './services/persona';

import type { Message, User, Attachment } from './types';
import { Sender } from './types';

import { AudioPlayerProvider } from './contexts/AudioPlayerContext';

/**
 * The main application component. Manages all application state, including authentication,
 * UI visibility, chat messages, and user settings. It serves as the central hub for
 * all interactions and modal dialogs.
 */
const App: React.FC = () => {
    // --- State Declarations ---

    // Auth state: Manages the current user and authentication status.
    const [currentUser, setCurrentUser] = useState<User | null>(null);
    const [authStatus, setAuthStatus] = useState<'loading' | 'authenticated' | 'unauthenticated'>('loading');

    // UI state: Controls the visibility of major UI components like the intro, home screen, and menus.
    const [showIntro, setShowIntro] = useState(true);
    const [showHomeScreen, setShowHomeScreen] = useState(true);
    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [isAgeGated, setIsAgeGated] = useState(localStorage.getItem('darenNexusAgeGate') !== 'true');
    const [isInputFocused, setIsInputFocused] = useState(false);

    // Home screen animation state for smooth transitions.
    const [selectedModeForAnimation, setSelectedModeForAnimation] = useState<string | null>(null);
    const mainContentRef = useRef<HTMLDivElement>(null);

    // Modal states: Toggles for all modal dialogs within the application.
    const [isHistoryOpen, setIsHistoryOpen] = useState(false);
    const [isAppearanceOpen, setIsAppearanceOpen] = useState(false);
    const [isVoiceSelectionOpen, setIsVoiceSelectionOpen] = useState(false);
    const [isModeSelectionOpen, setIsModeSelectionOpen] = useState(false);
    const [isBugModalOpen, setIsBugModalOpen] = useState(false);
    const [isVoiceInputOpen, setIsVoiceInputOpen] = useState(false);
    const [isLiveVoiceOpen, setIsLiveVoiceOpen] = useState(false);
    const [isVoicePreviewLoading, setIsVoicePreviewLoading] = useState<string | null>(null);
    const [isNexusAndChillOpen, setIsNexusAndChillOpen] = useState(false);
    const [isForgotPasswordOpen, setIsForgotPasswordOpen] = useState(false);
    const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
    const [isMemoryVaultOpen, setIsMemoryVaultOpen] = useState(false);


    // Chat state: Manages messages, user input, attachments, and loading indicators.
    const [messages, setMessages] = useState<Message[]>([]);
    const [input, setInput] = useState('');
    const [attachments, setAttachments] = useState<{ file: File; base64: string }[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [isExtraThinking, setIsExtraThinking] = useState(false);
    const [ttsLoadingMessageId, setTtsLoadingMessageId] = useState<string | null>(null);
    const abortControllerRef = useRef<AbortController | null>(null);

    // Settings state: Manages the AI's persona, model, voice, and visual settings.
    const [currentMode, setCurrentMode] = useState('Vibing');
    const [currentAiModel, setCurrentAiModel] = useState('gemini-2.5-pro'); // Default model set to Pro 2.5
    const [ttsVoice, setTtsVoice] = useState('Fenrir');
    const [textZoom, setTextZoom] = useState(100);
    const [theme, setTheme] = useState('theme-default');
    const [liveSystemInstruction, setLiveSystemInstruction] = useState(initialSystemInstruction);

    // --- Effects ---

    const prevThemeRef = useRef(theme);
    /**
     * Manages global CSS classes on the `<body>` element based on theme and chat state.
     * This allows for global styling changes like background gradients and layout adjustments.
     */
    useEffect(() => {
        const bodyClassList = document.body.classList;

        // Theme Management: Remove previous theme, add current theme for global styling.
        bodyClassList.remove(prevThemeRef.current);
        bodyClassList.add(theme);
        prevThemeRef.current = theme;

        // In-Chat State: Applies a class when not on the home screen to change backgrounds.
        if (!showHomeScreen) {
            bodyClassList.add('in-chat');
        } else {
            bodyClassList.remove('in--chat');
        }
    }, [theme, showHomeScreen]);

    /**
     * Applies a global glow effect to the screen border when any voice mode is active.
     */
    useEffect(() => {
        const bodyClassList = document.body.classList;
        if (isVoiceInputOpen || isLiveVoiceOpen) {
            bodyClassList.add('voice-mode-active-glow');
        } else {
            bodyClassList.remove('voice-mode-active-glow');
        }
        // Cleanup on unmount
        return () => {
            bodyClassList.remove('voice-mode-active-glow');
        }
    }, [isVoiceInputOpen, isLiveVoiceOpen]);

    /**
     * Toggles a 'is-typing' class on the body when the message input is focused.
     * Useful for subtle UI changes during input.
     */
    useEffect(() => {
        if(isInputFocused) {
            document.body.classList.add('is-typing');
        } else {
            document.body.classList.remove('is-typing');
        }
    }, [isInputFocused]);

    /**
     * Enables vertical scrolling on the body only when the authentication screen is visible.
     */
    useEffect(() => {
        if (authStatus === 'unauthenticated') {
            document.body.classList.add('auth-visible');
        } else {
            document.body.classList.remove('auth-visible');
        }
    }, [authStatus]);

    /**
     * Checks for a current user session on initial application load.
     * Sets the authentication status accordingly.
     */
    useEffect(() => {
        const user = getCurrentUser();
        if (user) {
            setCurrentUser(user);
            setAuthStatus('authenticated');
        } else {
            setAuthStatus('unauthenticated');
        }
    }, []);

    /**
     * Loads all user-specific data from persistence when a user is authenticated.
     * This includes chat history, settings, and persona instructions.
     */
    useEffect(() => {
        if (currentUser) {
            const loadUserData = async () => {
                const [
                    storedMessages,
                    storedInstruction,
                    storedVoice,
                    storedZoom,
                    storedTheme,
                ] = await Promise.all([
                    getCurrentSession(currentUser.hash),
                    getLiveSystemInstruction(currentUser.hash),
                    getTtsVoice(currentUser.hash),
                    getTextZoom(currentUser.hash),
                    getTheme(currentUser.hash),
                ]);

                if (storedMessages && storedMessages.length > 0) {
                    setMessages(storedMessages);
                    setShowHomeScreen(false);
                } else {
                    setMessages([]);
                    setShowHomeScreen(true);
                }
                setLiveSystemInstruction(storedInstruction ?? initialSystemInstruction);
                setTtsVoice(storedVoice ?? 'Fenrir');
                setTextZoom(storedZoom ?? 100);
                setTheme(storedTheme ?? 'theme-default');
            };
            loadUserData();
        }
    }, [currentUser]);

    /**
     * Persists the current chat session to local storage whenever messages change.
     */
    useEffect(() => {
        if (currentUser) {
            saveCurrentSession(currentUser.hash, messages);
        }
    }, [messages, currentUser]);

    // --- Handlers ---

    const handleLogin = async (email: string, password: string, rememberMe: boolean) => {
        const user = loginOrSignup(email, password, rememberMe);
        setCurrentUser(user);
        setAuthStatus('authenticated');
    };

    const handleGuest = async () => {
        const user = continueAsGuest();
        setCurrentUser(user);
        setAuthStatus('authenticated');
    };

    const handleGoToAuth = () => {
        setIsMenuOpen(false);
        setIsHistoryOpen(false); // Close any open modals
        // Delay auth change to allow modals to close gracefully
        setTimeout(() => {
          logout(); // This clears hashes from storage
          setCurrentUser(null);
          setMessages([]);
          setAuthStatus('unauthenticated');
        }, 300);
    };

    const handleLogout = () => {
        logout();
        setCurrentUser(null);
        setMessages([]);
        setAuthStatus('unauthenticated');
    };

    const handleAgeGateAgree = () => {
        localStorage.setItem('darenNexusAgeGate', 'true');
        setIsAgeGated(false);
    };

    /**
     * Archives the current chat session (if it has content) and starts a new one.
     */
    const handleNewChat = async () => {
        if (!currentUser) return;
        if (messages.length > 0) {
            await archiveCurrentSession(currentUser.hash);
        }
        setMessages([]);
        setShowHomeScreen(true);
        setIsMenuOpen(false);
    };

    const handleSelectSession = (sessionMessages: Message[]) => {
        setMessages(sessionMessages);
        setShowHomeScreen(false);
        setIsHistoryOpen(false);
    };

    /**
     * Aborts the in-flight API request for generating an AI response.
     */
    const handleCancelGeneration = () => {
        if (abortControllerRef.current) {
          abortControllerRef.current.abort();
        }
    };

    /**
     * The core function for sending a message. It handles trigger phrases,
     * sends the message to the backend, and processes the AI's response,
     * including initiating background text-to-speech generation.
     */
    const handleSendMessage = useCallback(async (messageText: string) => {
        if (isLoading || (!messageText.trim() && attachments.length === 0)) return;
        if (!currentUser) return;

        // --- Trigger Phrase Checks for special client-side actions ---
        const lowerCaseText = messageText.trim().toLowerCase();
        if (lowerCaseText === 'nexus who') {
            window.open('/nexus-who.html', '_blank');
            return;
        }
        if (['can i come over', 'nexus and chill', 'nexus & chill'].includes(lowerCaseText)) {
            setIsNexusAndChillOpen(true);
            return;
        }

        setIsLoading(true);
        if (['Deep Dive', 'Mentor Mode'].includes(currentMode)) {
            setIsExtraThinking(true);
        }

        setShowHomeScreen(false);
        setInput('');

        abortControllerRef.current = new AbortController();

        const userMessageAttachments: Attachment[] = attachments.map(a => ({
            type: 'image',
            base64: a.base64,
            mimeType: a.file.type,
        }));

        const userMessage: Message = {
            id: Date.now().toString(),
            text: messageText,
            sender: Sender.User,
            timestamp: new Date().toISOString(),
            attachments: userMessageAttachments,
        };

        let messagesToSend = [...messages, userMessage];
        const messagesAddedCount = 1;
        setMessages(messagesToSend);

        // Automatically switch to 'Crimson Hell' theme if intent is sexual.
        const intent = await classifyTextIntent(messageText);
        if (intent === 'sexual' && theme !== 'theme-crimson') {
            handleThemeChange('theme-crimson');
            const transitionMessage: Message = {
                id: (Date.now() + 0.5).toString(),
                text: "mmm okk... shit! It's getting HOT in this mofo. 🔥😈💦",
                sender: Sender.AI,
                timestamp: new Date().toISOString()
            };
            // Add transition message to history for context
            messagesToSend = [...messagesToSend, transitionMessage];
            // messagesAddedCount++;
            setMessages(messagesToSend);
        }

        const currentAttachments = [...attachments];
        setAttachments([]);

        try {
            // FIX: Corrected the arguments for `sendMessage` and handle the response object.
            // Send the complete context to the backend API.
            const response = await sendMessage(
                messageText,
                currentMode,
                messagesToSend,
                currentUser ?? undefined,
                currentAiModel,
                currentAttachments,
                null, // quotedMessage
                {}, // options
                abortControllerRef.current.signal
            );

            const aiResponseText = response.text;
            const groundingMetadata = response.groundingMetadata;

            const aiMessageId = (Date.now() + 1).toString();
            const aiMessage: Message = {
                id: aiMessageId,
                text: aiResponseText,
                sender: Sender.AI,
                timestamp: new Date().toISOString(),
                groundingMetadata: groundingMetadata,
            };

            // Add the text message first to provide a fast response to the user.
            setMessages(prev => [...prev, aiMessage]);

            // Now, generate speech in the background and update the message with the audio buffer.
            try {
                setTtsLoadingMessageId(aiMessageId);
                const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
                // FIX: Pass the response text string to generateSpeech, not the whole response object.
                const audioBuffer = await generateSpeech(aiResponseText, audioContext, ttsVoice);

                setMessages(prev => prev.map(msg => 
                    msg.id === aiMessageId ? { ...msg, audioBuffer } : msg
                ));
            } catch (speechError) {
                console.error("Error generating speech after response:", speechError);
            } finally {
                setTtsLoadingMessageId(null);
            }

        } catch (error: any) {
            if (error.name === 'AbortError') {
                console.log('Message generation cancelled by user.');
                // Remove the optimistically added messages
                setMessages(prev => prev.slice(0, -messagesAddedCount));
                setIsLoading(false);
                setIsExtraThinking(false);
                return;
            }

            console.error("Error sending message:", error);
            const errorMessage: Message = {
                id: (Date.now() + 1).toString(),
                text: error.message || "Sorry, I ran into an error. Please try again.",
                sender: Sender.AI,
                timestamp: new Date().toISOString(),
            };
            setMessages(prev => [...prev, errorMessage]);
        } finally {
            setIsLoading(false);
            setIsExtraThinking(false);
            abortControllerRef.current = null;
        }
    }, [isLoading, attachments, currentUser, currentMode, messages, liveSystemInstruction, currentAiModel, ttsVoice, theme]);

    /**
     * Handles the selection of a new "vibe" from the home screen,
     * triggering a transition animation before switching to the chat view.
     */
    const handleSelectMode = (mode: string) => {
        setSelectedModeForAnimation(mode);
        setTimeout(() => {
            setCurrentMode(mode);
            setShowHomeScreen(false);
            setSelectedModeForAnimation(null);
        }, 2000); // 2-second delay allows the user to see the selection animation.
    };

    const handleAnimationComplete = useCallback(() => {
      mainContentRef.current?.scrollTo({
        top: mainContentRef.current.scrollHeight,
        behavior: 'smooth',
      });
    }, []);

    const handleThemeChange = (newTheme: string) => {
        setTheme(newTheme);
        if (currentUser) saveTheme(currentUser.hash, newTheme);
    };

    const handleTextZoomChange = (zoom: number) => {
        setTextZoom(zoom);
        if (currentUser) saveTextZoom(currentUser.hash, zoom);
    };

    const handleVoiceChange = (voice: string) => {
        setTtsVoice(voice);
        if (currentUser) saveTtsVoice(currentUser.hash, voice);
    };

    /**
     * Generates and plays a preview of a TTS voice.
     */
    const handlePreviewTtsVoice = async (voice: string, text: string) => {
        setIsVoicePreviewLoading(voice);
        try {
            const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
            const buffer = await generateSpeech(text, audioContext, voice);
            return buffer;
        } catch (error) {
            console.error("Error previewing voice:", error);
        } finally {
            setIsVoicePreviewLoading(null);
        }
    };

    const fileInputRef = React.useRef<HTMLInputElement>(null);

    const handleFileSelect = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file && file.type.startsWith('image/')) {
            const reader = new FileReader();
            reader.onload = (loadEvent) => {
                const base64 = (loadEvent.target?.result as string).split(',')[1];
                setAttachments(prev => [...prev, { file, base64 }]);
            };
            reader.readAsDataURL(file);
        }
        if (fileInputRef.current) fileInputRef.current.value = '';
    };

    const handleRemoveAttachment = (indexToRemove: number) => {
        setAttachments(prev => prev.filter((_, index) => index !== indexToRemove));
    };

    const handleSaveProfile = async (newName: string) => {
        if (currentUser && !currentUser.isGuest) {
            const updatedUser = await saveCurrentUserName(currentUser.hash, newName);
            if (updatedUser) {
                setCurrentUser(updatedUser);
            }
            setIsProfileModalOpen(false);
        }
    };

    // --- Render Logic ---

    if (authStatus === 'loading') {
        return <InitialLoading />;
    }

    if (authStatus === 'unauthenticated') {
        return (
            <>
                <div className="w-full min-h-full flex items-center justify-center animate-auth-emerge opacity-0">
                    <AuthScreen onLogin={handleLogin} onGuest={handleGuest} onForgotPassword={() => setIsForgotPasswordOpen(true)} />
                </div>
                <ForgotPasswordModal isOpen={isForgotPasswordOpen} onClose={() => setIsForgotPasswordOpen(false)} />
            </>
        );
    }

    if (!currentUser) {
       return <div className="w-full min-h-full flex items-center justify-center"><p>Error: No user found.</p></div>;
    }

    if (showIntro) {
        return <Intro onIntroComplete={() => setShowIntro(false)} />;
    }

    if (isAgeGated) {
        return <AgeGatingModal onAgree={handleAgeGateAgree} />;
    }

    return (
      <AudioPlayerProvider>
        <div className={`w-full h-full flex flex-col font-sans transition-colors duration-500 global-edge-glow`}>
            <Header
                onToggleMenu={() => setIsMenuOpen(!isMenuOpen)}
                onNewChat={handleNewChat}
                showHomeScreen={showHomeScreen}
                onGoHome={() => setShowHomeScreen(true)}
                onOpenBugModal={() => setIsBugModalOpen(true)}
                currentMode={currentMode}
                onModeChange={setCurrentMode}
            />

            <Menu
                isOpen={isMenuOpen}
                onClose={() => setIsMenuOpen(false)}
                onLogout={handleLogout}
                onViewHistory={() => { setIsHistoryOpen(true); setIsMenuOpen(false); }}
                currentAiModel={currentAiModel}
                onSelectAiModel={setCurrentAiModel}
                onOpenAppearance={() => { setIsAppearanceOpen(true); setIsMenuOpen(false); }}
                onOpenVoiceSelection={() => { setIsVoiceSelectionOpen(true); setIsMenuOpen(false); }}
                onOpenModeSelection={() => { setIsModeSelectionOpen(true); setIsMenuOpen(false); }}
                currentUser={currentUser}
                onGoToAuth={handleGoToAuth}
                onOpenProfileModal={() => { setIsProfileModalOpen(true); setIsMenuOpen(false); }}
                onOpenMemoryVault={() => { setIsMemoryVaultOpen(true); setIsMenuOpen(false); }}
            />

            <main ref={mainContentRef} className={`flex-1 flex flex-col overflow-y-auto min-h-0 smooth-scroll`}>
                {showHomeScreen ? (
                    <Home onSelectMode={handleSelectMode} onAnimationComplete={handleAnimationComplete} currentMode={currentMode} selectedModeForAnimation={selectedModeForAnimation} />
                ) : (
                    <ChatWindow messages={messages} isLoading={isLoading} isExtraThinking={isExtraThinking} onCancelGeneration={handleCancelGeneration} textZoom={textZoom} ttsLoadingMessageId={ttsLoadingMessageId} />
                )}
            </main>

            {!showHomeScreen && (
                <MessageInput
                    input={input}
                    setInput={setInput}
                    onSendMessage={handleSendMessage}
                    isLoading={isLoading}
                    isListening={isVoiceInputOpen}
                    onToggleListening={() => setIsVoiceInputOpen(!isVoiceInputOpen)}
                    onToggleLiveVoiceMode={() => setIsLiveVoiceOpen(true)}
                    attachments={attachments}
                    onFileSelect={handleFileSelect}
                    onRemoveAttachment={handleRemoveAttachment}
                    setIsInputFocused={setIsInputFocused}
                />
            )}

            {/* Modals */}
            {currentUser && <ChatHistory isOpen={isHistoryOpen} onClose={() => setIsHistoryOpen(false)} onSelectSession={handleSelectSession} currentUser={currentUser} onSignUp={handleGoToAuth} />}
            <AppearanceModal isOpen={isAppearanceOpen} onClose={() => setIsAppearanceOpen(false)} textZoom={textZoom} onTextZoomChange={handleTextZoomChange} currentTheme={theme} onThemeChange={handleThemeChange} />
            <VoiceSelectionModal isOpen={isVoiceSelectionOpen} onClose={() => setIsVoiceSelectionOpen(false)} currentTtsVoice={ttsVoice} onSelectTtsVoice={handleVoiceChange} onPreviewTtsVoice={handlePreviewTtsVoice} isVoicePreviewLoading={isVoicePreviewLoading} />
            <ModeSelectionModal isOpen={isModeSelectionOpen} onClose={() => setIsModeSelectionOpen(false)} onSelectMode={handleSelectMode} currentMode={currentMode} />
            <BugReportModal isOpen={isBugModalOpen} onClose={() => setIsBugModalOpen(false)} />
            <ProfileModal isOpen={isProfileModalOpen} onClose={() => setIsProfileModalOpen(false)} currentUser={currentUser} onSave={handleSaveProfile} />
            {currentUser && <MemoryVaultModal isOpen={isMemoryVaultOpen} onClose={() => setIsMemoryVaultOpen(false)} currentUser={currentUser} />}
            {isVoiceInputOpen && <VoiceInputOverlay onClose={() => setIsVoiceInputOpen(false)} onSend={handleSendMessage} />}
            {isLiveVoiceOpen && <LiveVoiceModeOverlay onClose={() => setIsLiveVoiceOpen(false)} onAddLiveMessages={(msgs) => setMessages(prev => [...prev, ...msgs])} systemInstruction={liveSystemInstruction} />}
            {currentUser && <NexusAndChillModal isOpen={isNexusAndChillOpen} onClose={() => setIsNexusAndChillOpen(false)} currentUser={currentUser} />}
            <ForgotPasswordModal isOpen={isForgotPasswordOpen} onClose={() => setIsForgotPasswordOpen(false)} />
        </div>
      </AudioPlayerProvider>
    );
}

export default App;

import React from 'react';
import { HistoryIcon } from './HistoryIcon';
import { LogoutIcon } from './LogoutIcon';
import { PaintBrushIcon } from './PaintBrushIcon';
import { SpeakerWaveIcon } from './SpeakerWaveIcon';
import { SwitchIcon } from './SwitchIcon';
import { Avatar } from './Avatar';
import { AppIcon } from './AppIcon';
import { CloseIcon } from './CloseIcon';
import { EditProfileIcon } from './EditProfileIcon';
import { VaultIcon } from './VaultIcon';
import type { User } from '../types';

interface MenuProps {
  isOpen: boolean;
  onClose: () => void;
  onLogout: () => void;
  onViewHistory: () => void;
  currentAiModel: string;
  onSelectAiModel: (model: string) => void;
  onOpenAppearance: () => void;
  onOpenVoiceSelection: () => void;
  onOpenModeSelection: () => void;
  currentUser: User;
  onGoToAuth: () => void;
  onOpenProfileModal: () => void;
  onOpenMemoryVault: () => void;
}

const aiModels = [
    { id: 'gemini-2.5-pro', name: 'DAREN Pro' },
    { id: 'gemini-2.5-flash', name: 'DAREN Flash' },
];

const MenuItem: React.FC<{
    icon: React.ReactNode;
    text: string;
    onClick: () => void;
    isDestructive?: boolean;
}> = ({ icon, text, onClick, isDestructive }) => (
    <button
        onClick={onClick}
        className={`btn-radiate-glow group w-full flex items-center gap-4 px-4 py-3 rounded-full text-left transition-colors duration-200 ${
            isDestructive 
            ? 'text-red-400 hover:bg-red-500/10 hover:text-red-300'
            : 'text-gray-300 hover:bg-white/10 hover:text-white'
        }`}
    >
        <div className="w-5 h-5 flex-shrink-0 flex items-center justify-center">{icon}</div>
        <span className="font-semibold text-base">{text}</span>
    </button>
);

export const Menu: React.FC<MenuProps> = ({ 
    isOpen,
    onClose,
    onLogout, 
    onViewHistory, 
    currentAiModel, 
    onSelectAiModel, 
    onOpenAppearance,
    onOpenVoiceSelection,
    onOpenModeSelection,
    currentUser,
    onGoToAuth,
    onOpenProfileModal,
    onOpenMemoryVault,
}) => {
    if (!isOpen) return null;

    return (
      <>
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-20" onClick={onClose}></div>
        <div className="fixed top-0 left-0 bottom-0 w-80 bg-[var(--modal-bg)] border-r border-[var(--ui-border-color)] shadow-2xl z-30 menu-slide-in transition-colors duration-500 flex flex-col">

            <div className="absolute inset-0 flex items-center justify-center opacity-5 pointer-events-none z-0">
                <div className="w-48 h-48">
                    <AppIcon />
                </div>
            </div>

            <div className="absolute top-4 right-4 z-20">
                <button onClick={onClose} className="p-2 rounded-full text-gray-400 hover:bg-white/10 hover:text-white transition-colors">
                    <CloseIcon />
                </button>
            </div>

            <div className="relative z-10 flex flex-col h-full">
                {/* Header */}
                <div className="p-4 pt-6">
                    {currentUser.isGuest ? (
                        <div className="text-center p-4 bg-white/5 rounded-2xl">
                            <h2 className="text-xl font-bold text-white">Hey Guest!</h2>
                            <p className="text-sm text-gray-400 mt-1">Create an account to save your history and settings.</p>
                            <button 
                                onClick={onGoToAuth}
                                className="w-full mt-4 bg-nexusPurple-600 text-white font-bold py-2 px-4 rounded-lg hover:bg-nexusPurple-700 transition-colors"
                            >
                                Create Account
                            </button>
                        </div>
                    ) : (
                         <div className="flex items-center gap-3 p-2">
                            <Avatar name={currentUser.name || currentUser.email} />
                            <div className="flex-1 min-w-0">
                                <h2 className="text-lg font-semibold text-white truncate">Hey {currentUser.name || currentUser.email.split('@')[0]}!</h2>
                            </div>
                            <button onClick={onOpenProfileModal} className="p-2 rounded-full text-gray-400 hover:bg-white/10 hover:text-white transition-colors">
                                <EditProfileIcon />
                            </button>
                        </div>
                    )}
                </div>

                <div className="p-4">
                    <p className="px-2 text-xs font-semibold text-gray-400 uppercase tracking-wider mb-2">AI Brain</p>
                    <div className="flex items-center bg-black/20 rounded-full p-1">
                        {aiModels.map(model => (
                            <button
                                key={model.id}
                                onClick={() => onSelectAiModel(model.id)}
                                className={`btn-radiate-glow w-1/2 px-2 py-1.5 text-sm font-semibold rounded-full transition-colors ${currentAiModel === model.id ? 'bg-nexusPurple-600 text-white' : 'text-gray-300 hover:bg-white/10'}`}
                            >
                                {model.name}
                            </button>
                        ))}
                    </div>
                </div>

                <div className="flex-1 p-4 space-y-2 overflow-y-auto no-scrollbar">
                    <MenuItem icon={<PaintBrushIcon />} text="Appearance" onClick={onOpenAppearance} />
                    <MenuItem icon={<SpeakerWaveIcon />} text="Voice" onClick={onOpenVoiceSelection} />
                    <MenuItem icon={<SwitchIcon />} text="Switch Vibe" onClick={onOpenModeSelection} />
                    <MenuItem icon={<HistoryIcon />} text="Chat History" onClick={onViewHistory} />
                    <MenuItem icon={<VaultIcon />} text="Memory Vault" onClick={onOpenMemoryVault} />
                </div>
                <div className="p-4 mt-auto">
                    <MenuItem icon={<LogoutIcon />} text="Logout" onClick={onLogout} isDestructive />
                </div>
            </div>
        </div>
      </>
    );
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { AuthScreen } from './components/AuthScreen';
import { ChatHistory } from './components/ChatHistory';
import { ChatWindow } from './components/ChatWindow';
import { Header } from './components/Header';
import { Home } from './components/Home';
import { InitialLoading } from './components/InitialLoading';
import { Intro } from './components/Intro';
import { Menu } from './components/Menu';
import { MessageInput } from './components/MessageInput';
import { AppearanceModal } from './components/AppearanceModal';
import { VoiceSelectionModal } from './components/VoiceSelectionModal';
import { ModeSelectionModal } from './components/ModeSelectionModal';
import { BugReportModal } from './components/BugReportModal';
import { VoiceInputOverlay } from './components/VoiceInputOverlay';
import { AgeGatingModal } from './components/AgeGatingModal';
import { LiveVoiceModeOverlay } from './components/LiveVoiceModeOverlay';
import { NexusAndChillModal } from './components/NexusAndChillModal';
import { ForgotPasswordModal } from './components/ForgotPasswordModal';
import { ProfileModal } from './components/ProfileModal';
import { MemoryVaultModal } from './components/MemoryVaultModal';

import { loginOrSignup, continueAsGuest, getCurrentUser, logout, saveCurrentUserName } from './services/authService';
import { archiveCurrentSession } from './services/chatHistoryService';
import { sendMessage } from './services/dialogflowService';
import { generateSpeech, classifyTextIntent } from './services/geminiService';
import {
  getCurrentSession,
  getLiveSystemInstruction,
  getTtsVoice,
  getTextZoom,
  getTheme,
  saveCurrentSession,
  saveTtsVoice,
  saveTextZoom,
  saveTheme,
} from './services/persistenceService';
import { initialSystemInstruction } from './services/persona';

import type { Message, User, Attachment } from './types';
import { Sender } from './types';

import { AudioPlayerProvider } from './contexts/AudioPlayerContext';

/**
 * The main application component. Manages all application state, including authentication,
 * UI visibility, chat messages, and user settings. It serves as the central hub for
 * all interactions and modal dialogs.
 */
const App: React.FC = () => {
    // --- State Declarations ---

    // Auth state: Manages the current user and authentication status.
    const [currentUser, setCurrentUser] = useState<User | null>(null);
    const [authStatus, setAuthStatus] = useState<'loading' | 'authenticated' | 'unauthenticated'>('loading');

    // UI state: Controls the visibility of major UI components like the intro, home screen, and menus.
    const [showIntro, setShowIntro] = useState(true);
    const [showHomeScreen, setShowHomeScreen] = useState(true);
    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [isAgeGated, setIsAgeGated] = useState(localStorage.getItem('darenNexusAgeGate') !== 'true');
    const [isInputFocused, setIsInputFocused] = useState(false);

    // Home screen animation state for smooth transitions.
    const [selectedModeForAnimation, setSelectedModeForAnimation] = useState<string | null>(null);
    const mainContentRef = useRef<HTMLDivElement>(null);

    // Modal states: Toggles for all modal dialogs within the application.
    const [isHistoryOpen, setIsHistoryOpen] = useState(false);
    const [isAppearanceOpen, setIsAppearanceOpen] = useState(false);
    const [isVoiceSelectionOpen, setIsVoiceSelectionOpen] = useState(false);
    const [isModeSelectionOpen, setIsModeSelectionOpen] = useState(false);
    const [isBugModalOpen, setIsBugModalOpen] = useState(false);
    const [isVoiceInputOpen, setIsVoiceInputOpen] = useState(false);
    const [isLiveVoiceOpen, setIsLiveVoiceOpen] = useState(false);
    const [isVoicePreviewLoading, setIsVoicePreviewLoading] = useState<string | null>(null);
    const [isNexusAndChillOpen, setIsNexusAndChillOpen] = useState(false);
    const [isForgotPasswordOpen, setIsForgotPasswordOpen] = useState(false);
    const [isProfileModalOpen, setIsProfileModalOpen] = useState(false);
    const [isMemoryVaultOpen, setIsMemoryVaultOpen] = useState(false);


    // Chat state: Manages messages, user input, attachments, and loading indicators.
    const [messages, setMessages] = useState<Message[]>([]);
    const [input, setInput] = useState('');
    const [attachments, setAttachments] = useState<{ file: File; base64: string }[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [isExtraThinking, setIsExtraThinking] = useState(false);
    const [ttsLoadingMessageId, setTtsLoadingMessageId] = useState<string | null>(null);
    const abortControllerRef = useRef<AbortController | null>(null);

    // Settings state: Manages the AI's persona, model, voice, and visual settings.
    const [currentMode, setCurrentMode] = useState('Vibing');
    const [currentAiModel, setCurrentAiModel] = useState('gemini-2.5-pro'); // Default model set to Pro
    const [ttsVoice, setTtsVoice] = useState('Fenrir');
    const [textZoom, setTextZoom] = useState(100);
    const [theme, setTheme] = useState('theme-default');
    const [liveSystemInstruction, setLiveSystemInstruction] = useState(initialSystemInstruction);

    // --- Effects ---

    const prevThemeRef = useRef(theme);
    /**
     * Manages global CSS classes on the `<body>` element based on theme and chat state.
     * This allows for global styling changes like background gradients and layout adjustments.
     */
    useEffect(() => {
        const bodyClassList = document.body.classList;

        // Theme Management: Remove previous theme, add current theme for global styling.
        bodyClassList.remove(prevThemeRef.current);
        bodyClassList.add(theme);
        prevThemeRef.current = theme;

        // In-Chat State: Applies a class when not on the home screen to change backgrounds.
        if (!showHomeScreen) {
            bodyClassList.add('in-chat');
        } else {
            bodyClassList.remove('in--chat');
        }
    }, [theme, showHomeScreen]);

    /**
     * Applies a global glow effect to the screen border when any voice mode is active.
     */
    useEffect(() => {
        const bodyClassList = document.body.classList;
        if (isVoiceInputOpen || isLiveVoiceOpen) {
            bodyClassList.add('voice-mode-active-glow');
        } else {
            bodyClassList.remove('voice-mode-active-glow');
        }
        // Cleanup on unmount
        return () => {
            bodyClassList.remove('voice-mode-active-glow');
        }
    }, [isVoiceInputOpen, isLiveVoiceOpen]);

    /**
     * Toggles a 'is-typing' class on the body when the message input is focused.
     * Useful for subtle UI changes during input.
     */
    useEffect(() => {
        if(isInputFocused) {
            document.body.classList.add('is-typing');
        } else {
            document.body.classList.remove('is-typing');
        }
    }, [isInputFocused]);

    /**
     * Enables vertical scrolling on the body only when the authentication screen is visible.
     */
    useEffect(() => {
        if (authStatus === 'unauthenticated') {
            document.body.classList.add('auth-visible');
        } else {
            document.body.classList.remove('auth-visible');
        }
    }, [authStatus]);

    /**
     * Checks for a current user session on initial application load.
     * Sets the authentication status accordingly.
     */
    useEffect(() => {
        const user = getCurrentUser();
        if (user) {
            setCurrentUser(user);
            setAuthStatus('authenticated');
        } else {
            setAuthStatus('unauthenticated');
        }
    }, []);

    /**
     * Loads all user-specific data from persistence when a user is authenticated.
     * This includes chat history, settings, and persona instructions.
     */
    useEffect(() => {
        if (currentUser) {
            const loadUserData = async () => {
                const [
                    storedMessages,
                    storedInstruction,
                    storedVoice,
                    storedZoom,
                    storedTheme,
                ] = await Promise.all([
                    getCurrentSession(currentUser.hash),
                    getLiveSystemInstruction(currentUser.hash),
                    getTtsVoice(currentUser.hash),
                    getTextZoom(currentUser.hash),
                    getTheme(currentUser.hash),
                ]);

                if (storedMessages && storedMessages.length > 0) {
                    setMessages(storedMessages);
                    setShowHomeScreen(false);
                } else {
                    setMessages([]);
                    setShowHomeScreen(true);
                }
                setLiveSystemInstruction(storedInstruction ?? initialSystemInstruction);
                setTtsVoice(storedVoice ?? 'Fenrir');
                setTextZoom(storedZoom ?? 100);
                setTheme(storedTheme ?? 'theme-default');
            };
            loadUserData();
        }
    }, [currentUser]);

    /**
     * Persists the current chat session to local storage whenever messages change.
     */
    useEffect(() => {
        if (currentUser) {
            saveCurrentSession(currentUser.hash, messages);
        }
    }, [messages, currentUser]);

    // --- Handlers ---

    const handleLogin = async (email: string, password: string, rememberMe: boolean) => {
        const user = loginOrSignup(email, password, rememberMe);
        setCurrentUser(user);
        setAuthStatus('authenticated');
    };

    const handleGuest = async () => {
        const user = continueAsGuest();
        setCurrentUser(user);
        setAuthStatus('authenticated');
    };

    const handleGoToAuth = () => {
        setIsMenuOpen(false);
        setIsHistoryOpen(false); // Close any open modals
        // Delay auth change to allow modals to close gracefully
        setTimeout(() => {
          logout(); // This clears hashes from storage
          setCurrentUser(null);
          setMessages([]);
          setAuthStatus('unauthenticated');
        }, 300);
    };

    const handleLogout = () => {
        logout();
        setCurrentUser(null);
        setMessages([]);
        setAuthStatus('unauthenticated');
    };

    const handleAgeGateAgree = () => {
        localStorage.setItem('darenNexusAgeGate', 'true');
        setIsAgeGated(false);
    };

    /**
     * Archives the current chat session (if it has content) and starts a new one.
     */
    const handleNewChat = async () => {
        if (!currentUser) return;
        if (messages.length > 0) {
            await archiveCurrentSession(currentUser.hash);
        }
        setMessages([]);
        setShowHomeScreen(true);
        setIsMenuOpen(false);
    };

    const handleSelectSession = (sessionMessages: Message[]) => {
        setMessages(sessionMessages);
        setShowHomeScreen(false);
        setIsHistoryOpen(false);
    };

    /**
     * Aborts the in-flight API request for generating an AI response.
     */
    const handleCancelGeneration = () => {
        if (abortControllerRef.current) {
          abortControllerRef.current.abort();
        }
    };

    /**
     * The core function for sending a message. It handles trigger phrases,
     * sends the message to the backend, and processes the AI's response,
     * including initiating background text-to-speech generation.
     */
    const handleSendMessage = useCallback(async (messageText: string) => {
        if (isLoading || (!messageText.trim() && attachments.length === 0)) return;
        if (!currentUser) return;

        // --- Trigger Phrase Checks for special client-side actions ---
        const lowerCaseText = messageText.trim().toLowerCase();
        if (lowerCaseText === 'nexus who') {
            window.open('/nexus-who.html', '_blank');
            return;
        }
        if (['can i come over', 'nexus and chill', 'nexus & chill'].includes(lowerCaseText)) {
            setIsNexusAndChillOpen(true);
            return;
        }

        setIsLoading(true);
        if (['Deep Dive', 'Mentor Mode'].includes(currentMode)) {
            setIsExtraThinking(true);
        }

        setShowHomeScreen(false);
        setInput('');

        abortControllerRef.current = new AbortController();

        const userMessageAttachments: Attachment[] = attachments.map(a => ({
            type: 'image',
            base64: a.base64,
            mimeType: a.file.type,
        }));

        const userMessage: Message = {
            id: Date.now().toString(),
            text: messageText,
            sender: Sender.User,
            timestamp: new Date().toISOString(),
            attachments: userMessageAttachments,
        };

        // History for the API call does NOT include the new user message.
        const historyForApi = [...messages];
        // Messages to add to the UI state.
        const newUiMessages: Message[] = [userMessage];

        const currentAttachments = [...attachments];
        setAttachments([]);

        // Handle intent classification and add UI-only transition message if needed
        const intent = await classifyTextIntent(messageText);
        if (intent === 'sexual' && theme !== 'theme-crimson') {
            handleThemeChange('theme-crimson');
            const transitionMessage: Message = {
                id: (Date.now() + 0.5).toString(),
                text: "mmm okk... shit! It's getting HOT in this mofo. 🔥😈💦",
                sender: Sender.AI,
                timestamp: new Date().toISOString()
            };
            newUiMessages.push(transitionMessage);
        }

        // Update UI state once with all new messages for this turn.
        setMessages(prev => [...prev, ...newUiMessages]);

        try {
            // Send the clean history and the new message text to the backend.
            const response = await sendMessage(
                messageText,
                currentMode,
                historyForApi, // Clean history
                currentUser ?? undefined,
                currentAiModel,
                currentAttachments,
                null, // quotedMessage
                {}, // options
                abortControllerRef.current.signal
            );

            const aiResponseText = response.text;
            const groundingMetadata = response.groundingMetadata;

            const aiMessageId = (Date.now() + 1).toString();
            const aiMessage: Message = {
                id: aiMessageId,
                text: aiResponseText,
                sender: Sender.AI,
                timestamp: new Date().toISOString(),
                groundingMetadata: groundingMetadata,
            };

            // Add the text message first to provide a fast response to the user.
            setMessages(prev => [...prev, aiMessage]);

            // Now, generate speech in the background and update the message with the audio buffer.
            try {
                setTtsLoadingMessageId(aiMessageId);
                const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
                const audioBuffer = await generateSpeech(aiResponseText, audioContext, ttsVoice);

                setMessages(prev => prev.map(msg => 
                    msg.id === aiMessageId ? { ...msg, audioBuffer } : msg
                ));
            } catch (speechError) {
                console.error("Error generating speech after response:", speechError);
            } finally {
                setTtsLoadingMessageId(null);
            }

        } catch (error: any) {
            if (error.name === 'AbortError') {
                console.log('Message generation cancelled by user.');
                // Revert the UI state by removing the messages we just added.
                setMessages(historyForApi); 
                setIsLoading(false);
                setIsExtraThinking(false);
                return;
            }

            console.error("Error sending message:", error);
            const errorMessage: Message = {
                id: (Date.now() + 1).toString(),
                text: error.message || "Sorry, I ran into an error. Please try again.",
                sender: Sender.AI,
                timestamp: new Date().toISOString(),
            };
            setMessages(prev => [...prev, errorMessage]);
        } finally {
            setIsLoading(false);
            setIsExtraThinking(false);
            abortControllerRef.current = null;
        }
    }, [isLoading, attachments, currentUser, currentMode, messages, liveSystemInstruction, currentAiModel, ttsVoice, theme]);

    /**
     * Handles the selection of a new "vibe" from the home screen,
     * triggering a transition animation before switching to the chat view.
     */
    const handleSelectMode = (mode: string) => {
        setSelectedModeForAnimation(mode);
        setTimeout(() => {
            setCurrentMode(mode);
            setShowHomeScreen(false);
            setSelectedModeForAnimation(null);
        }, 2000); // 2-second delay allows the user to see the selection animation.
    };

    const handleAnimationComplete = useCallback(() => {
      mainContentRef.current?.scrollTo({
        top: mainContentRef.current.scrollHeight,
        behavior: 'smooth',
      });
    }, []);

    const handleThemeChange = (newTheme: string) => {
        setTheme(newTheme);
        if (currentUser) saveTheme(currentUser.hash, newTheme);
    };

    const handleTextZoomChange = (zoom: number) => {
        setTextZoom(zoom);
        if (currentUser) saveTextZoom(currentUser.hash, zoom);
    };

    const handleVoiceChange = (voice: string) => {
        setTtsVoice(voice);
        if (currentUser) saveTtsVoice(currentUser.hash, voice);
    };

    /**
     * Generates and plays a preview of a TTS voice.
     */
    const handlePreviewTtsVoice = async (voice: string, text: string) => {
        setIsVoicePreviewLoading(voice);
        try {
            const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
            const buffer = await generateSpeech(text, audioContext, voice);
            return buffer;
        } catch (error) {
            console.error("Error previewing voice:", error);
        } finally {
            setIsVoicePreviewLoading(null);
        }
    };

    const fileInputRef = React.useRef<HTMLInputElement>(null);

    const handleFileSelect = (event: React.ChangeEvent<HTMLInputElement>) => {
        const file = event.target.files?.[0];
        if (file && file.type.startsWith('image/')) {
            const reader = new FileReader();
            reader.onload = (loadEvent) => {
                const base64 = (loadEvent.target?.result as string).split(',')[1];
                setAttachments(prev => [...prev, { file, base64 }]);
            };
            reader.readAsDataURL(file);
        }
        if (fileInputRef.current) fileInputRef.current.value = '';
    };

    const handleRemoveAttachment = (indexToRemove: number) => {
        setAttachments(prev => prev.filter((_, index) => index !== indexToRemove));
    };

    const handleSaveProfile = async (newName: string) => {
        if (currentUser && !currentUser.isGuest) {
            const updatedUser = await saveCurrentUserName(currentUser.hash, newName);
            if (updatedUser) {
                setCurrentUser(updatedUser);
            }
            setIsProfileModalOpen(false);
        }
    };

    // --- Render Logic ---

    if (authStatus === 'loading') {
        return <InitialLoading />;
    }

    if (authStatus === 'unauthenticated') {
        return (
            <>
                <div className="w-full min-h-full flex items-center justify-center animate-auth-emerge opacity-0">
                    <AuthScreen onLogin={handleLogin} onGuest={handleGuest} onForgotPassword={() => setIsForgotPasswordOpen(true)} />
                </div>
                <ForgotPasswordModal isOpen={isForgotPasswordOpen} onClose={() => setIsForgotPasswordOpen(false)} />
            </>
        );
    }

    if (!currentUser) {
       return <div className="w-full min-h-full flex items-center justify-center"><p>Error: No user found.</p></div>;
    }

    if (showIntro) {
        return <Intro onIntroComplete={() => setShowIntro(false)} />;
    }

    if (isAgeGated) {
        return <AgeGatingModal onAgree={handleAgeGateAgree} />;
    }

    return (
      <AudioPlayerProvider>
        <div className={`w-full h-full flex flex-col font-sans transition-colors duration-500 global-edge-glow`}>
            <Header
                onToggleMenu={() => setIsMenuOpen(!isMenuOpen)}
                onNewChat={handleNewChat}
                showHomeScreen={showHomeScreen}
                onGoHome={() => setShowHomeScreen(true)}
                onOpenBugModal={() => setIsBugModalOpen(true)}
                currentMode={currentMode}
                onModeChange={setCurrentMode}
            />

            <Menu
                isOpen={isMenuOpen}
                onClose={() => setIsMenuOpen(false)}
                onLogout={handleLogout}
                onViewHistory={() => { setIsHistoryOpen(true); setIsMenuOpen(false); }}
                currentAiModel={currentAiModel}
                onSelectAiModel={setCurrentAiModel}
                onOpenAppearance={() => { setIsAppearanceOpen(true); setIsMenuOpen(false); }}
                onOpenVoiceSelection={() => { setIsVoiceSelectionOpen(true); setIsMenuOpen(false); }}
                onOpenModeSelection={() => { setIsModeSelectionOpen(true); setIsMenuOpen(false); }}
                currentUser={currentUser}
                onGoToAuth={handleGoToAuth}
                onOpenProfileModal={() => { setIsProfileModalOpen(true); setIsMenuOpen(false); }}
                onOpenMemoryVault={() => { setIsMemoryVaultOpen(true); setIsMenuOpen(false); }}
            />

            <main ref={mainContentRef} className={`flex-1 flex flex-col overflow-y-auto min-h-0 smooth-scroll`}>
                {showHomeScreen ? (
                    <Home onSelectMode={handleSelectMode} onAnimationComplete={handleAnimationComplete} currentMode={currentMode} selectedModeForAnimation={selectedModeForAnimation} />
                ) : (
                    <ChatWindow messages={messages} isLoading={isLoading} isExtraThinking={isExtraThinking} onCancelGeneration={handleCancelGeneration} textZoom={textZoom} ttsLoadingMessageId={ttsLoadingMessageId} />
                )}
            </main>

            {!showHomeScreen && (
                <MessageInput
                    input={input}
