                    <div className="h-2 w-2 animate-dot-bounce rounded-full bg-white" style={{ animationDelay: '0.2s' }}></div>
                    <div className="h-2 w-2 animate-dot-bounce rounded-full bg-white" style={{ animationDelay: '0.4s' }}></div>
