    return (
      <AudioPlayerProvider>
        <div ref={appContainerRef} className={`w-full h-full flex flex-col font-sans transition-colors duration-500 global-edge-glow`}>
            <Header
                onToggleMenu={() => setIsMenuOpen(!isMenuOpen)}
