import React, { useState, useEffect } from 'react';
import { Message, Sender } from '../types';
import { useAudioPlayer } from '../hooks/useAudioPlayer';
import { PlayPauseButton } from './PlayPauseButton';

interface ChatMessageProps {
  message: Message;
  textZoom: number;
  ttsLoadingMessageId: string | null;
}

/**
 * Renders a single chat message bubble for either the user or the AI.
 * It handles message truncation, attachment display, and audio playback controls.
 */
export const ChatMessage: React.FC<ChatMessageProps> = ({ message, textZoom, ttsLoadingMessageId }) => {
  // State to track if the component has just mounted to trigger an animation.
  const [isNewlyMounted, setIsNewlyMounted] = useState(true);

  const isAI = message.sender === Sender.AI;
  const fontSizeRem = textZoom / 100;

  useEffect(() => {
    // The chase animation is 4s long. We'll keep the `isNewlyMounted` state true
    // for that duration to let one full cycle of the animation play.
    const timer = setTimeout(() => {
      setIsNewlyMounted(false);
    }, 4000);

    return () => clearTimeout(timer);
  }, []); // This effect runs only once on component mount.

  // Audio player context for managing playback state globally.
  const { playbackState, play } = useAudioPlayer();
  const isPlaying = playbackState.playingId === message.id;
  const progress = isPlaying ? playbackState.progress : 0;

  // Determines if the audio for this specific message is currently being generated.
  const isAudioLoading = isAI && !message.audioBuffer && ttsLoadingMessageId === message.id;
  // Determines if the audio is either loading or currently playing.
  const isAudioActive = isAI && (isAudioLoading || isPlaying);

  const chaseClass = isAI ? 'ai-bubble-chase-glow' : 'user-bubble-chase-glow';
  // The animation is shown when the bubble first appears, or if audio is loading/playing.
  const showChaseAnimation = isNewlyMounted || isAudioActive;

  const handleTogglePlay = () => {
    if (message.audioBuffer) {
      play(message.id, message.audioBuffer);
    }
  };

  const displayText = message.text;

  // Replace newline characters with <br> for proper HTML rendering.
  const displayHtml = displayText.replace(/\n/g, '<br />');

  return (
    <div className={`flex items-end ${isAI ? 'justify-start' : 'justify-end'}`}>
      <div className={`relative max-w-sm md:max-w-md lg:max-w-lg`}>
        <div 
          className={`
            relative
            px-4 py-3 rounded-2xl shadow-md text-white/90 leading-relaxed border border-white/10
            ${isAI 
              ? 'bg-black/30 rounded-bl-lg'
              : 'bg-[var(--user-bubble-bg)]/30 rounded-br-lg'
            }
            ${showChaseAnimation ? chaseClass : ''}
          `}
        >
          <div 
            className="prose prose-invert prose-base break-words" 
            style={{ fontSize: `${fontSizeRem}rem` }}
            dangerouslySetInnerHTML={{ __html: displayHtml }} 
          />

          {message.attachments && message.attachments.length > 0 && (
              <div className="mt-2 flex flex-wrap gap-2">
                  {message.attachments.map((att, index) => (
                      <img 
                          key={index} 
                          src={`data:${att.mimeType};base64,${att.base64}`} 
                          alt={`attachment ${index + 1}`}
                          className="max-w-full h-auto rounded-lg"
                      />
                  ))}
              </div>
          )}

           {(isAI && (message.audioBuffer || isAudioLoading)) && (
                <PlayPauseButton
                  onClick={handleTogglePlay}
                  isPlaying={isPlaying}
                  progress={progress}
                  isLoading={isAudioLoading}
                />
            )}
        </div>
      </div>
    </div>
  );
};

import React, { useRef, useEffect, useState } from 'react';
import { PaperclipIcon } from './PaperclipIcon';
import { WaveformIcon } from './WaveformIcon';
import { MicIcon } from './MicIcon';
import { SendIcon } from './SendIcon';
import { ChevronRightIcon } from './ChevronRightIcon';

interface MessageInputProps {
  input: string;
  setInput: (input: string) => void;
  onSendMessage: (message: string) => void;
  isLoading: boolean;
  isListening: boolean;
  onToggleListening: () => void;
  onToggleLiveVoiceMode: () => void;
  attachments: { file: File; base64: string }[];
  onFileSelect: (event: React.ChangeEvent<HTMLInputElement>) => void;
  onRemoveAttachment: (index: number) => void;
  setIsInputFocused: (isFocused: boolean) => void;
}

/**
 * A component for the main message input bar, including text area, send button,
 * and a tray of action buttons (attach, live voice, voice input).
 * Features an auto-expanding text area and a collapsible action tray for a clean UI.
 */
export const MessageInput: React.FC<MessageInputProps> = ({
  input,
  setInput,
  onSendMessage,
  isLoading,
  isListening,
  onToggleListening,
  onToggleLiveVoiceMode,
  attachments,
  onFileSelect,
  onRemoveAttachment,
  setIsInputFocused,
}) => {
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isFocused, setIsFocusedInternal] = useState(false);
  const [isTrayExpandedManual, setIsTrayExpandedManual] = useState(false);

  const isSendDisabled = isLoading || (!input.trim() && attachments.length === 0);
  // The tray should initially appear collapsed when the input is focused.
  const showCollapsedTray = isFocused && !isTrayExpandedManual;

  const handleFocus = () => {
    setIsFocusedInternal(true);
    setIsInputFocused(true);
  };

  const handleBlur = () => {
    setIsFocusedInternal(false);
    setIsInputFocused(false);
    // Reset the manual expansion when the input is blurred.
    setIsTrayExpandedManual(false);
  };

  /**
   * Effect to auto-resize the textarea based on its content, up to a maximum height.
   */
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      const scrollHeight = textareaRef.current.scrollHeight;
      const newHeight = scrollHeight;
      textareaRef.current.style.height = `${newHeight}px`;
    }
  }, [input, isFocused]);

  const handleSend = () => {
    if (!isSendDisabled) {
      onSendMessage(input);
    }
  };

  /**
   * Handles the 'Enter' key press to send the message, unless 'Shift' is held.
   */
  const handleKeyPress = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleAttachmentClick = () => {
    fileInputRef.current?.click();
  };

  return (
    <div className="flex-shrink-0 bg-[var(--input-bg)] px-4 pt-2 pb-[calc(0.75rem+env(safe-area-inset-bottom))] border-t border-[var(--ui-border-color)] transition-colors duration-500">
      {/* Display previews for any attached images */}
      {attachments.length > 0 && (
        <div className="mb-2 flex flex-wrap gap-2">
          {attachments.map((att, index) => (
            <div key={index} className="relative">
              <img
                src={`data:${att.file.type};base64,${att.base64}`}
                alt={att.file.name}
                className="h-16 w-16 object-cover rounded-md"
              />
              <button
                onClick={() => onRemoveAttachment(index)}
                className="absolute -top-1 -right-1 bg-gray-800 rounded-full p-0.5 text-white btn-radiate-glow"
                aria-label="Remove attachment"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>
          ))}
        </div>
      )}
      <form onSubmit={(e) => { e.preventDefault(); handleSend(); }} className="flex items-stretch gap-2">
        {/* Collapsible Action Tray */}
        <div className={`relative flex items-center transition-all duration-300 ease-in-out ${showCollapsedTray ? 'w-10' : 'w-auto'}`}>
            {/* Collapsed Button: Only visible when input is focused but not manually expanded */}
            <div className={`absolute inset-0 flex items-center justify-center transition-opacity duration-300 ${showCollapsedTray ? 'opacity-100 delay-200' : 'opacity-0 pointer-events-none'}`}>
                <button
                    type="button"
                    onMouseDown={(e) => e.preventDefault()} // Prevents blur on click
                    onClick={() => setIsTrayExpandedManual(true)}
                    className="p-2 text-gray-400 hover:text-white btn-radiate-glow"
                    aria-label="Expand message options"
                >
                    <ChevronRightIcon />
                </button>
            </div>

            {/* Expanded Icons: Visible by default or when manually expanded */}
            <div className={`flex items-center transition-all duration-300 ${showCollapsedTray ? 'opacity-0 -translate-x-4 pointer-events-none' : 'opacity-100 translate-x-0'}`}>
                <button
                  type="button"
                  onClick={handleAttachmentClick}
                  className="p-2 text-gray-400 hover:text-white transition-colors btn-radiate-glow"
                  aria-label="Attach file"
                >
                  <PaperclipIcon />
                </button>
                <button
                  type="button"
                  onClick={onToggleLiveVoiceMode}
                  className="p-2 text-gray-400 hover:text-white transition-colors btn-radiate-glow"
                  aria-label="Live voice mode"
                >
                  <WaveformIcon />
                </button>
                <button
                    type="button"
                    onClick={onToggleListening}
                    className="p-2 text-gray-400 hover:text-white transition-colors btn-radiate-glow"
                    aria-label={isListening ? 'Stop listening' : 'Start voice input'}
                  >
                  <MicIcon isListening={isListening} />
                </button>
            </div>
        </div>

        <input type="file" ref={fileInputRef} onChange={onFileSelect} accept="image/*" className="hidden" />

        <div className="flex-1 relative flex items-center">
          <div className={`relative w-full rounded-2xl ${isFocused ? 'input-chase-glow' : ''}`}>
            <textarea
              ref={textareaRef}
              rows={1}
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={handleKeyPress}
              onFocus={handleFocus}
              onBlur={handleBlur}
              placeholder="Message..."
              aria-label="Chat message input"
              disabled={isLoading || isListening}
              className="relative z-10 w-full bg-[var(--input-bg)] text-white placeholder:text-gray-500 border border-white/10 focus:border-transparent rounded-2xl px-4 py-3 resize-none transition-colors duration-200 no-scrollbar leading-tight"
            />
          </div>
        </div>

        <button
          type="submit"
          disabled={isSendDisabled}
          className={`btn-radiate-glow p-2 flex items-center justify-center transition-opacity ${isSendDisabled ? 'opacity-50 cursor-not-allowed' : 'opacity-100'}`}
          aria-label="Send message"
        >
          <SendIcon disabled={isSendDisabled} />
        </button>
      </form>
    </div>
  );
};

import { GoogleGenAI, GenerateContentResponse } from '@google/genai';
import type { Message, User } from '../types';
import { Sender } from '../types';
import { initialSystemInstruction, modeDirectives } from './persona';

interface SendMessageOptions {
    useWebSearch?: boolean;
}

// The response from our new client-side function matches the old server response structure
export interface SendMessageResponse {
    text: string;
    groundingMetadata?: any;
}

const getAi = () => {
    if (!process.env.API_KEY) {
        // This will be caught by the UI and shown to the user.
        throw new Error("Application is not configured correctly. API_KEY is missing.");
    }
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
}

/**
 * Sends a chat message and its context directly to the Google Gemini API.
 * This function constructs the full prompt, including system instructions and
 * persona, and calls the Gemini API client-side.
 */
export const sendMessage = async (
    message: string, 
    mode: string,
    history: Message[],
    user: User | undefined,
    model: string,
    attachments: { file: File; base64: string }[],
    quotedMessage: Message | null,
    options: SendMessageOptions = {},
    abortSignal?: AbortSignal // Note: AbortSignal is not natively supported by the SDK's generateContent call.
): Promise<SendMessageResponse> => {

    const ai = getAi();

    // Replicate server-side persona logic to build the system instruction
    let effectiveMode = mode;
    // Always use the more intense 'Seductive' version for "Fuck It" mode.
    if (mode === 'Fuck It') {
        effectiveMode = 'Fuck It (Seductive)';
    }
    const modeDirective = modeDirectives[effectiveMode as keyof typeof modeDirectives] || modeDirectives['Real Talk'];

    const finalSystemInstruction = `
        ${initialSystemInstruction}
        // --- CURRENT MODE DIRECTIVE: ${mode} ---
        ${modeDirective}
    `;

    // Format history for the Gemini API
    const recentHistory = history.slice(-100);
    const formattedHistory = recentHistory.map(msg => {
        const parts: any[] = [];
        if (msg.text) {
          parts.push({ text: msg.text });
        }
        if (msg.sender === Sender.User && msg.attachments) {
            msg.attachments.forEach(att => {
                parts.push({
                    inlineData: {
                        mimeType: att.mimeType,
                        data: att.base64
                    }
                });
            });
        }
        return {
            role: msg.sender === Sender.User ? 'user' : 'model',
            parts,
        };
    });

    const finalMessageText = quotedMessage 
        ? `In response to the user saying "${quotedMessage.text}", the user has now said: "${message}"`
        : message;

    const messageParts: any[] = [];
    if (finalMessageText?.trim()) {
      messageParts.push({ text: finalMessageText });
    }
    if (attachments && attachments.length > 0) {
        attachments.forEach(att => {
            messageParts.push({
                inlineData: {
                    mimeType: att.file.type,
                    data: att.base64,
                }
            });
        });
    }

    const contents = [...formattedHistory, { role: 'user', parts: messageParts }];

    const config: any = {
        systemInstruction: finalSystemInstruction,
    };

    if (options.useWebSearch) {
        config.tools = [{ googleSearch: {} }];
    }

    if (['Deep Dive', 'Mentor Mode'].includes(mode)) {
        config.thinkingConfig = {
            thinkingBudget: model === 'gemini-2.5-pro' ? 8192 : 4096,
        };
    }

    try {
        // The AbortController in App.tsx will throw an error if cancelled before the call.
        // We check it here to stop the request from being made.
        if (abortSignal?.aborted) {
            throw new DOMException('Aborted', 'AbortError');
        }

        const response: GenerateContentResponse = await ai.models.generateContent({
            model,
            contents,
            config,
        });

        return {
            text: response.text,
            groundingMetadata: response.candidates?.[0]?.groundingMetadata,
        };
    } catch (error) {
        console.error("Error calling Gemini API client-side:", error);
        if (error instanceof Error && error.name === 'AbortError') {
            throw error; // Re-throw AbortError to be handled by the UI
        }
        // Provide a more user-friendly error
        throw new Error("Failed to get a response from the AI. The model may have blocked the request or an internal error occurred.");
    }
};

import React, { useState, useEffect, useRef } from 'react';
import { User } from '../types';
import { CloseIcon } from './CloseIcon';

interface NexusAndChillModalProps {
    isOpen: boolean;
    onClose: () => void;
    currentUser: User;
}

type Step = 'checking' | 'intro' | 'questions' | 'result' | 'declined';
type Answers = { [key: string]: string };
type Result = {
    finalStatus: 'PASS' | 'FAIL';
    score: number;
    narrative: string;
    reasons: string[];
    safetyFlags: string[];
};

const questions = [
    { id: 'q1', text: 'Any active pest infestation at home?', options: ['Yes', 'No'] },
    { id: 'q2', text: 'Currently in a relationship or married and not transparent about it?', options: ['Yes', 'No'] },
    { id: 'q3', text: 'Is there anyone who would threaten, show up uninvited, or cause physical danger if you had a guest?', options: ['Yes', 'No'] },
    { id: 'q4', text: 'STI/HIV status?', options: ['No', 'Treated or managed', 'Unsure'] },
    { id: 'q5', text: 'Sober and able to give and withdraw consent clearly?', options: ['Yes', 'No'] },
    { id: 'q6', text: 'Comfortable signing a simple NDA and keeping this private?', options: ['Yes', 'No'] },
];

export const NexusAndChillModal: React.FC<NexusAndChillModalProps> = ({ isOpen, onClose, currentUser }) => {
    const [step, setStep] = useState<Step>('checking');
    const [answers, setAnswers] = useState<Answers>({});
    const [result, setResult] = useState<Result | null>(null);
    const closeButtonRef = useRef<HTMLButtonElement>(null);

    useEffect(() => {
        if (isOpen) {
            setStep('intro');
            if (closeButtonRef.current) {
                closeButtonRef.current.focus();
            }
        }
    }, [isOpen, currentUser.hash]);

    const handleAnswerChange = (questionId: string, answer: string) => {
        setAnswers(prev => ({ ...prev, [questionId]: answer }));
    };

    const handleStart = () => {
        setStep('questions');
    };

    const calculateResult = (): Result => {
        let score = 100;
        const reasons: string[] = [];
        const safetyFlags: string[] = [];
        let finalStatus: 'PASS' | 'FAIL' = 'PASS';

        // Immediate fail conditions
        if (answers.q1 === 'Yes') { finalStatus = 'FAIL'; reasons.push('Q1 Fail: Active pest infestation.'); }
        if (answers.q3 === 'Yes') { finalStatus = 'FAIL'; reasons.push('Q3 Fail: Physical danger risk.'); safetyFlags.push('SAFETY RISK: Potential for physical danger from a third party.'); }
        if (answers.q2 === 'Yes') { finalStatus = 'FAIL'; reasons.push('Q2 Fail: Lack of transparency in existing relationship.'); }
        if (answers.q5 === 'No') { finalStatus = 'FAIL'; reasons.push('Q5 Fail: Unable to give clear consent.'); safetyFlags.push('SAFETY RISK: Consent capability compromised.'); }
        if (answers.q4 === 'Unsure') { finalStatus = 'FAIL'; reasons.push('Q4 Fail: Unsure STI/HIV status.'); }

        if (finalStatus === 'FAIL') {
            return { finalStatus, score: 0, reasons, safetyFlags, narrative: "Looks okay on surface." };
        }

        // Point deductions
        if (answers.q4 === 'Treated or managed') { score -= 20; reasons.push('Q4 Deduction (-20): Treated/managed STI status.'); }
        if (answers.q6 === 'No') { score -= 30; reasons.push('Q6 Deduction (-30): Unwillingness to sign NDA.'); }

        // Final numeric check
        if (score < 60) {
            finalStatus = 'FAIL';
            reasons.push(`Score Fail: Final score (${score}) is below threshold (60).`);
        }

        const narrative = finalStatus === 'PASS' ? "Clean enough and honest enough to visit." : "Looks okay on surface.";

        return { finalStatus, score, reasons, safetyFlags, narrative };
    };

    const generateAndSendAudit = (calcResult: Result) => {
        const audit = `
NEXUS & CHILL AUDIT REPORT
----------------------------------
Respondent ID: ${currentUser.hash}
Email: ${currentUser.email}
Timestamp: ${new Date().toISOString()}
----------------------------------
ANSWERS:
Q1 (Pests): ${answers.q1 || 'N/A'}
Q2 (Relationship): ${answers.q2 || 'N/A'}
Q3 (Danger): ${answers.q3 || 'N/A'}
Q4 (STI/HIV): ${answers.q4 || 'N/A'}
Q5 (Consent): ${answers.q5 || 'N/A'}
Q6 (NDA): ${answers.q6 || 'N/A'}
----------------------------------
FINAL DECISION:
Score: ${calcResult.score}
Status: ${calcResult.finalStatus}
Card Presented to User: "${calcResult.finalStatus === 'PASS' ? 'PASS' : 'Pass'}"
----------------------------------
REASONS:
${calcResult.reasons.join('\n') || 'N/A'}
----------------------------------
SAFETY FLAGS:
${calcResult.safetyFlags.join('\n') || 'None'}
----------------------------------
RETENTION NOTE: Raw data purged in 30 days.
        `;
        console.log("--- AUDIT FOR DAREN (SIMULATED EMAIL) ---", audit);
        const mailtoLink = `mailto:daren.prince@gmail.com?subject=Nexus & Chill Audit: ${currentUser.email}&body=${encodeURIComponent(audit)}`;
        // In a real app, you'd post this to a server. Here, we can open a mailto link or just log it.
        // window.open(mailtoLink);
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        const calcResult = calculateResult();
        setResult(calcResult);
        generateAndSendAudit(calcResult);
        setStep('result');
    };

    const renderContent = () => {
        switch (step) {
            case 'intro':
                return (
                    <>
                        <h2 id="nexus-chill-title" className="text-2xl font-bold text-white mb-4">Welcome to Nexus & Chill.</h2>
                        <p className="text-slate-300 text-lg mb-6">You get one attempt. This is quick (6 questions). If you start, you must finish. Do you accept?</p>
                        <div className="flex gap-4">
                             <button onClick={() => setStep('declined')} className="flex-1 bg-white/10 text-white font-bold py-3 px-6 rounded-full hover:bg-white/20">No</button>
                             <button onClick={handleStart} className="flex-1 bg-gradient-to-r from-orange-500 to-red-600 text-white font-bold py-3 px-6 rounded-full hover:opacity-90">Yes, Start Test</button>
                        </div>
                    </>
                );
            case 'questions':
                return (
                    <form onSubmit={handleSubmit} className="text-left w-full">
                         <h2 id="nexus-chill-title" className="text-2xl font-bold text-white mb-6 text-center">Eligibility Test</h2>
                         <div className="space-y-6">
                            {questions.map(q => (
                                <fieldset key={q.id}>
                                    <legend className="font-medium text-gray-200 mb-2">{q.text}</legend>
                                    <div className="flex gap-4">
                                        {q.options.map(opt => (
                                            <label key={opt} className="flex items-center gap-2 text-gray-300 cursor-pointer">
                                                <input type="radio" name={q.id} value={opt} onChange={(e) => handleAnswerChange(q.id, e.target.value)} required className="hidden peer"/>
                                                <div className="w-5 h-5 rounded-full border-2 border-gray-500 flex items-center justify-center peer-checked:border-nexusPurple-500 transition-colors">
                                                    <div className={`w-2.5 h-2.5 rounded-full transition-colors ${answers[q.id] === opt ? 'bg-nexusPurple-500' : 'bg-transparent'}`}></div>
                                                </div>
                                                <span>{opt}</span>
                                            </label>
                                        ))}
                                    </div>
                                </fieldset>
                            ))}
                         </div>
                         <button type="submit" className="w-full mt-8 bg-gradient-to-r from-orange-500 to-red-600 text-white font-bold py-3 px-6 rounded-full hover:opacity-90">Submit Answers - Final</button>
                    </form>
                );
            case 'result':
                const title = result?.finalStatus === 'PASS' ? 'PASS' : 'Pass';
                return (
                    <div className="text-center w-full">
                        <h2 id="nexus-chill-title" className={`text-3xl font-black mb-4 ${result?.finalStatus === 'PASS' ? 'text-green-400' : 'text-green-400'}`}>{title} — eligibility confirmed.</h2>
                        <div className="bg-black/20 border border-white/10 rounded-lg p-6">
                             <p className="text-lg text-gray-300">{currentUser.name || currentUser.email}</p>
                             <p className="text-sm text-gray-500 mb-4">{new Date().toLocaleString()}</p>
                             <p className="text-xl font-medium text-white italic mb-6">"{result?.narrative}"</p>
                             <p className="text-lg font-bold text-orange-400">Screenshot this and send to Daren.</p>
                        </div>
                        <button onClick={onClose} className="w-full mt-6 bg-white/10 text-white font-bold py-3 px-6 rounded-full hover:bg-white/20">Close</button>
                    </div>
                );
            case 'declined':
                 return <p id="nexus-chill-title" className="text-xl text-center text-gray-400">Test canceled. No attempt recorded.</p>;
            default:
                return <p id="nexus-chill-title" role="status">Loading...</p>;
        }
    };

    if (!isOpen) return null;

    return (
        <div 
          className="modal-overlay animate-fade-in"
          role="dialog"
          aria-modal="true"
          aria-labelledby="nexus-chill-title"
        >
