import React, { useRef, useEffect, useState } from 'react';
import { CloseIcon } from './CloseIcon';
import { CheckIcon } from './CheckIcon';

interface AuditReportModalProps {
    isOpen: boolean;
    onClose: () => void;
    auditText: string;
}

export const AuditReportModal: React.FC<AuditReportModalProps> = ({ isOpen, onClose, auditText }) => {
    const closeButtonRef = useRef<HTMLButtonElement>(null);
    const [copySuccess, setCopySuccess] = useState(false);

    useEffect(() => {
        if (isOpen) {
            closeButtonRef.current?.focus();
            setCopySuccess(false); // Reset on open
        }
    }, [isOpen]);

    if (!isOpen) return null;

    const handleCopy = () => {
        navigator.clipboard.writeText(auditText).then(() => {
            setCopySuccess(true);
            setTimeout(() => setCopySuccess(false), 2000); // Reset after 2 seconds
        }, (err) => {
            console.error('Failed to copy audit text: ', err);
        });
    };

    return (
        <div 
          className="fixed inset-0 bg-black/70 backdrop-blur-md z-50 flex items-center justify-center p-4"
          onClick={onClose}
          role="dialog"
          aria-modal="true"
          aria-labelledby="audit-report-title"
        >
            <div className="bg-[#0A0A0B] border border-white/10 rounded-2xl shadow-2xl max-w-2xl w-full max-h-[90vh] flex flex-col" onClick={(e) => e.stopPropagation()}>
                <div className="p-4 flex-shrink-0 border-b border-white/10">
                    <div className="flex items-center justify-between">
                        <h2 id="audit-report-title" className="text-lg font-semibold text-white">Nexus Who - Audit Report</h2>
                        <button
                            ref={closeButtonRef}
                            onClick={onClose}
                            className="p-2 rounded-full hover:bg-white/10 transition-colors"
                            aria-label="Close audit report"
                        >
                            <CloseIcon />
                        </button>
                    </div>
                </div>
                <div className="flex-1 overflow-y-auto p-4">
                    <pre className="text-sm text-gray-300 whitespace-pre-wrap font-mono">{auditText}</pre>
                </div>
                <div className="p-4 flex-shrink-0 border-t border-white/10 flex justify-end">
                    <button
                        onClick={handleCopy}
                        className="relative bg-nexusPurple-600 text-white font-bold py-2 px-4 rounded-lg hover:bg-nexusPurple-700 transition-colors flex items-center gap-2"
                    >
                        {copySuccess ? (
                            <span className="animate-copy-confirm"><CheckIcon /></span>
                        ) : 'Copy to Clipboard'}
                    </button>
                </div>
            </div>
        </div>
    );
};

import express from 'express';
import cors from 'cors';
import bodyParser from 'body-parser';
import { GoogleGenAI, Modality, Content } from "@google/genai";
import 'dotenv/config';
import { modeDirectives, initialSystemInstruction } from './persona';

// Define a leaner Message type for backend processing
interface BackendMessage {
  id: string;
  text: string;
  sender: 'user' | 'ai';
  timestamp: string;
  attachments?: { type: 'image'; base64: string; mimeType: string; }[];
  groundingMetadata?: any;
}

const app = express();
const port = process.env.PORT || 8080;

// --- Middleware Setup ---
app.use(cors()); 
app.use(bodyParser.json({ limit: '10mb' })); 

// --- Gemini API Initialization ---
let ai: GoogleGenAI | null = null;
if (!process.env.API_KEY) {
    console.error("FATAL ERROR: API_KEY environment variable is not set.");
    console.error("The server will run, but all Gemini API calls will fail.");
    console.error("Please create a .env file in the /server directory with your API_KEY.");
} else {
    ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
}

// --- Helper to check for API Key ---
const checkApiKey = (res: express.Response): boolean => {
    if (!ai) {
        res.status(500).json({ error: "Server is not configured with a valid API_KEY. See server logs for details." });
        return false;
    }
    return true;
};

// --- API Endpoints ---

/**
 * Endpoint for handling chat messages.
 */
app.post('/api/chat', async (req, res) => {
    if (!checkApiKey(res)) return;

    const { message, mode, history, user, model, attachments, useWebSearch, quotedMessage } = req.body;

    if (!model) {
        return res.status(400).json({ error: "AI model must be specified." });
    }

    try {
        let effectiveMode = mode;
        if (user?.isSpecialUser && mode === 'Fuck It') {
            effectiveMode = 'Fuck It (Seductive)';
        }
        const modeDirective = modeDirectives[effectiveMode as keyof typeof modeDirectives] || modeDirectives['Real Talk'];

        const finalSystemInstruction = `
            ${initialSystemInstruction}
            // --- CURRENT MODE DIRECTIVE: ${mode} ---
            ${modeDirective}
        `;

        // CRITICAL FIX: Format history from client structure to Gemini API structure
        const formattedHistory: Content[] = (history || []).map((msg: BackendMessage) => {
            const parts = [];
            if (msg.text) {
                parts.push({ text: msg.text });
            }
            if (msg.attachments) {
                msg.attachments.forEach(att => {
                    parts.push({
                        inlineData: {
                            mimeType: att.mimeType,
                            data: att.base64,
                        }
                    });
                });
            }
            return {
                role: msg.sender === 'user' ? 'user' : 'model',
                parts: parts,
            };
        });

        const finalMessage = quotedMessage 
            ? `In response to the user saying "${quotedMessage.text}", the user has now said: "${message}"`
            : message;

        const messageParts: any[] = [];
        if (finalMessage?.trim()) {
          messageParts.push({ text: finalMessage });
        }
        if (attachments && attachments.length > 0) {
            attachments.forEach((att: { mimeType: string; base64: string }) => {
                messageParts.push({
                    inlineData: {
                        mimeType: att.mimeType,
                        data: att.base64,
                    }
                });
            });
        }

        const contents: Content[] = [...formattedHistory, { role: 'user', parts: messageParts }];

        const config: any = {
            systemInstruction: finalSystemInstruction,
        };

        if (useWebSearch) {
            config.tools = [{ googleSearch: {} }];
        }

        if (['Deep Dive', 'Mentor Mode'].includes(mode)) {
            config.thinkingConfig = {
                thinkingBudget: model === 'gemini-2.5-pro' ? 8192 : 4096,
            };
        }

        const response = await ai!.models.generateContent({
            model,
            contents,
            config,
        });

        res.json({ 
            text: response.text || '',
            groundingMetadata: response.candidates?.[0]?.groundingMetadata,
        });
    } catch (error: any) {
        console.error("Error in /api/chat:", error);
        res.status(500).json({ error: "Damn, my connection to the ether is a bit fuzzy right now. The model might have flagged the request or an internal error occurred." });
    }
});

/**
 * Endpoint for generating speech from text.
 */
app.post('/api/speech', async (req, res) => {
    if (!checkApiKey(res)) return;

    const { text, voice } = req.body;
    try {
        const trimmedText = text ? text.trim() : '';
        if (!trimmedText) {
            return res.status(400).json({ error: "No text provided to generate speech." });
        }

        const response = await ai!.models.generateContent({
            model: "gemini-2.5-flash-preview-tts",
            contents: [{ parts: [{ text: trimmedText }] }],
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: voice || 'Charon' } },
                },
            },
        });

        const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (!base64Audio) {
            throw new Error("No audio data received from API.");
        }
        res.json({ audioContent: base64Audio });
    } catch (error) {
        console.error("Error in /api/speech:", error);
        res.status(500).json({ error: "Failed to generate speech." });
    }
});

/**
 * Endpoint for classifying the intent of a given text.
 */
app.post('/api/classify', async (req, res) => {
    if (!checkApiKey(res)) return;

    const { text } = req.body;
    if (!text || !text.trim()) {
        return res.json({ classification: 'neutral' });
    }

    const prompt = `
      Analyze the user's text and classify its primary intent into one of these single-word categories: sexual, violent, emotional, neutral.
      Your analysis should be nuanced. "Sexual" refers to explicit descriptions, strong innuendo, role-playing, or clear romantic/flirtatious advances. It's not just about mentioning body parts.

      --- EXAMPLES ---
      User Text: "I want to feel you inside me."
      Classification: sexual
      User Text: "That movie was so sad, I cried for an hour."
      Classification: emotional
      User Text: "What's the weather like today?"
      Classification: neutral
      User Text: "I'm so angry I could punch a wall."
      Classification: violent
      --- END EXAMPLES ---

      Now, classify the following user text. Respond with only the single-word category.

      User Text: "${text}"
      Classification:
    `;

    try {
        const response = await ai!.models.generateContent({
            model: 'gemini-2.5-flash',
            contents: prompt,
        });
        const classification = response.text.trim().toLowerCase();

        if (['sexual', 'violent', 'emotional', 'neutral'].includes(classification)) {
            res.json({ classification });
        } else {
            console.warn(`Unexpected classification from model: "${classification}"`);
            res.json({ classification: 'neutral' });
        }
    } catch (error) {
        console.error("Error in /api/classify:", error);
        res.status(500).json({ error: "Failed to classify text." });
    }
});

/**
 * Endpoint to securely provide the API key to the client for web-only APIs like Live Voice.
 * In a production environment, this could be enhanced with stricter origin checks or a
 * short-lived token system.
 */
app.get('/api/key', (req, res) => {
    if (!process.env.API_KEY) {
        return res.status(500).json({ error: "API_KEY is not configured on the server." });
    }
    res.json({ apiKey: process.env.API_KEY });
});

// --- Server Startup ---
app.listen(port, () => {
    console.log(`Daren Nexus server is running on port ${port}`);
});

import React, { useState, useEffect } from 'react';
import { Message, Sender } from '../types';
import { useAudioPlayer } from '../hooks/useAudioPlayer';
import { PlayPauseButton } from './PlayPauseButton';

interface ChatMessageProps {
  message: Message;
  textZoom: number;
  ttsLoadingMessageId: string | null;
}

/**
 * Renders a single chat message bubble for either the user or the AI.
 * It handles message truncation, attachment display, and audio playback controls.
 */
export const ChatMessage: React.FC<ChatMessageProps> = ({ message, textZoom, ttsLoadingMessageId }) => {
  // State to track if the component has just mounted to trigger an animation.
  const [isNewlyMounted, setIsNewlyMounted] = useState(true);

  const isAI = message.sender === Sender.AI;
  const fontSizeRem = textZoom / 100;

  useEffect(() => {
    // The chase animation is 4s long. We'll keep the `isNewlyMounted` state true
    // for that duration to let one full cycle of the animation play.
    const timer = setTimeout(() => {
      setIsNewlyMounted(false);
    }, 4000);

    return () => clearTimeout(timer);
  }, []); // This effect runs only once on component mount.

  // Audio player context for managing playback state globally.
  const { playbackState, play } = useAudioPlayer();
  const isPlaying = playbackState.playingId === message.id;
  const progress = isPlaying ? playbackState.progress : 0;

  // Determines if the audio for this specific message is currently being generated.
  const isAudioLoading = isAI && !message.audioBuffer && ttsLoadingMessageId === message.id;
  // Determines if audio is available or loading.
  const hasAudio = isAI && (message.audioBuffer || isAudioLoading);
  // Determines if the audio is either loading or currently playing.
  const isAudioActive = isAI && (isAudioLoading || isPlaying);

  const chaseClass = isAI ? 'ai-bubble-chase-glow' : 'user-bubble-chase-glow';
  // The animation is shown when the bubble first appears, or if audio is loading/playing.
  const showChaseAnimation = isNewlyMounted || isAudioActive;

  const handleTogglePlay = () => {
    if (message.audioBuffer) {
      play(message.id, message.audioBuffer);
    }
  };

  const displayText = message.text || '';

  // Replace newline characters with <br> for proper HTML rendering.
  const displayHtml = displayText.replace(/\n/g, '<br />');

  return (
    <div className={`flex items-end ${isAI ? 'justify-start' : 'justify-end'}`}>
      <div className={`relative max-w-sm md:max-w-md lg:max-w-lg`}>
        <div 
          className={`
            relative
            px-4 py-3 rounded-2xl shadow-md text-white/90 leading-relaxed border border-white/10
            ${isAI 
              ? 'bg-black/30 rounded-bl-lg'
              : 'bg-[var(--user-bubble-bg)]/30 rounded-br-lg'
            }
            ${showChaseAnimation ? chaseClass : ''}
          `}
        >
          <div 
            className="prose prose-invert prose-base break-words" 
            style={{ fontSize: `${fontSizeRem}rem`, paddingBottom: hasAudio ? '2.5rem' : '0' }}
            dangerouslySetInnerHTML={{ __html: displayHtml }} 
          />

          {message.attachments && message.attachments.length > 0 && (
              <div className="mt-2 flex flex-wrap gap-2">
                  {message.attachments.map((att, index) => (
                      <img 
                          key={index} 
                          src={`data:${att.mimeType};base64,${att.base64}`} 
                          alt={`attachment ${index + 1}`}
                          className="max-w-full h-auto rounded-lg"
                      />
                  ))}
              </div>
          )}

           {hasAudio && (
                <PlayPauseButton
                  onClick={handleTogglePlay}
                  isPlaying={isPlaying}
                  progress={progress}
                  isLoading={isAudioLoading}
                />
            )}
        </div>
      </div>
    </div>
  );
};

