    }

    return (
        <AudioPlayerProvider>
            <div ref={appContainerRef} className="h-full flex flex-col bg-black">
                <Header 
                    onToggleMenu={() => setIsMenuOpen(true)}
                    onNewChat={handleNewChat}
                    showHomeScreen={showHomeScreen}
