                />
                <main ref={mainContentRef} className="flex-1 flex flex-col overflow-y-auto smooth-scroll">
                    {showHomeScreen ? (
                        <Home 
                            onSelectMode={handleSelectMode}
                            onAnimationComplete={() => {}}
                            currentMode={currentMode}
                            selectedModeForAnimation={selectedModeForAnimation}
                        />
                    ) : (
                        <ChatWindow 
                            messages={messages} 
                            isLoading={isLoading} 
                            isExtraThinking={isExtraThinking}
                            onCancelGeneration={handleCancelGeneration}
                            textZoom={textZoom}
