interface SendMessageOptions {
    useWebSearch?: boolean;
}

// The response from our backend matches this structure
export interface SendMessageResponse {
    text: string;
    groundingMetadata?: any;
}

/**
 * Sends a chat message and its context to the application's backend server.
 * The server will then securely call the Google Gemini API with the full persona.
 */
export const sendMessage = async (
    message: string, 
    mode: string,
    history: Message[],
    user: User | undefined,
    model: string,
    attachments: { file: File; base64: string }[],
    quotedMessage: Message | null,
    options: SendMessageOptions = {},
    abortSignal?: AbortSignal
): Promise<SendMessageResponse> => {

    try {
        // Construct the request body for the backend server
        const body = {
            message,
            mode,
            // Strip non-serializable AudioBuffer from history before sending
            history: history.map(({ audioBuffer, ...rest }) => rest), 
            user,
            model,
            // Strip non-serializable File object from attachments
            attachments: attachments.map(a => ({ base64: a.base64, mimeType: a.file.type })),
            quotedMessage,
            useWebSearch: options.useWebSearch,
        };

        const response = await fetch(`${API_BASE_URL}/api/chat`, { // FIX: Use the full backend URL
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify(body),
            signal: abortSignal,
        });

        if (!response.ok) {
            const errorData = await response.json().catch(() => ({ error: 'An unknown server error occurred.' }));
            throw new Error(errorData.error || `Server responded with status: ${response.status}`);
        }

        const data: SendMessageResponse = await response.json();
        return data;

    } catch (error) {
        console.error("Error calling chat API via server:", error);
        if (error instanceof Error && error.name === 'AbortError') {
            throw error; // Re-throw AbortError to be handled by the UI
        }
        // Provide a user-friendly error for network or server issues
        throw new Error("Failed to connect to the Nexus server. Is it running?");
    }
};

import { decode, decodeAudioData } from '../utils/audioUtils';
import { API_BASE_URL } from '../config';

/**
 * Generates speech from text by calling the application's backend server.
 * @param text The text to be converted to speech.
 * @param audioContext The browser's AudioContext for decoding.
 * @param voice The desired voice for the speech synthesis.
 * @returns A promise that resolves to a playable AudioBuffer.
 */
export const generateSpeech = async (text: string, audioContext: AudioContext, voice: string): Promise<AudioBuffer> => {
    try {
        const trimmedText = text.trim();
        if (!trimmedText) {
            throw new Error("No text provided to generate speech.");
        }

        const response = await fetch(`${API_BASE_URL}/api/speech`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ text: trimmedText, voice }),
        });

        if (!response.ok) {
            const errorData = await response.json().catch(() => ({ error: 'Failed to generate speech.' }));
            throw new Error(errorData.error);
        }

        const { audioContent } = await response.json();
        if (!audioContent) {
            throw new Error("No audio data received from server.");
        }

        const decodedBytes = decode(audioContent);
        return await decodeAudioData(decodedBytes, audioContext, 24000, 1);

    } catch (error) {
        console.error("Error fetching speech from server:", error);
        throw error;
    }
};

/**
 * Classifies the intent of text by calling the application's backend server.
 * @param text The text to classify.
 * @returns A promise that resolves to the classification string (e.g., 'sexual').
 */
export const classifyTextIntent = async (text: string): Promise<string> => {
    if (!text.trim()) return 'neutral';

    try {
        const response = await fetch(`${API_BASE_URL}/api/classify`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ text }),
        });

        if (!response.ok) {
            console.error('Classification API failed:', response.statusText);
            return 'neutral'; // Default to neutral on API error
        }

        const { classification } = await response.json();
        return classification || 'neutral';
    } catch (error) {
        console.error("Error fetching classification from server:", error);
        return 'neutral'; // Default to neutral on network error
    }
};

import React, { useState, useEffect } from 'react';
import { NexusOrb } from './NexusOrb';
import { LoadingAnimation } from './LoadingAnimation';
import { ModeTiles } from './ModeTiles';
import { Embers } from './Embers';
import { LogoIcon } from './LogoIcon';

interface HomeProps {
  onSelectMode: (mode: string) => void;
  onAnimationComplete: () => void;
  currentMode: string;
  selectedModeForAnimation: string | null;
}

const H1_FULL_TEXT = "Sup? I'm Daren";
const P1_FULL_TEXT = "Ask me anything";
const P2_FULL_TEXT = "Let's get into it. What's the vibe?";
const TYPING_SPEED = 50; // ms per character

type IntroStep = 'loading' | 'content' | 'finished';

export const Home: React.FC<HomeProps> = ({ onSelectMode, onAnimationComplete, currentMode, selectedModeForAnimation }) => {
    const [introStep, setIntroStep] = useState<IntroStep>(() => {
        return sessionStorage.getItem('homeAnimationPlayed') ? 'finished' : 'loading';
    });

    const [isFlameVisible, setIsFlameVisible] = useState(introStep === 'finished');
    const [igniteFlame, setIgniteFlame] = useState(false);
    const [typingStep, setTypingStep] = useState(introStep === 'finished' ? 4 : 0);
    const [h1Text, setH1Text] = useState(introStep === 'finished' ? H1_FULL_TEXT : '');
    const [p1Text, setP1Text] = useState(introStep === 'finished' ? P1_FULL_TEXT : '');
    const [p2Text, setP2Text] = useState(introStep === 'finished' ? P2_FULL_TEXT : '');

    useEffect(() => {
        if (introStep === 'loading') {
            sessionStorage.setItem('homeAnimationPlayed', 'true');
        } else if (introStep === 'content') {
            setIsFlameVisible(true);
            setIgniteFlame(true);
            setTimeout(() => {
                setTypingStep(1);
            }, 700); // Start typing after flame ignites
        }
    }, [introStep]);

    useEffect(() => {
        if (igniteFlame) {
            const timer = setTimeout(() => {
                setIgniteFlame(false); // Remove class after it plays
            }, 700);
            return () => clearTimeout(timer);
        }
    }, [igniteFlame]);

    const handleLoadingComplete = () => {
        setIntroStep('content');
    };

    useEffect(() => {
        if (typingStep === 0 || typingStep > 3) return;

        let targetText: string;
        let setText: React.Dispatch<React.SetStateAction<string>>;

        if (typingStep === 1) {
            targetText = H1_FULL_TEXT;
            setText = setH1Text;
        } else if (typingStep === 2) {
            targetText = P1_FULL_TEXT;
            setText = setP1Text;
        } else { // typingStep === 3
            targetText = P2_FULL_TEXT;
            setText = setP2Text;
        }

        let i = 0;
        const intervalId = setInterval(() => {
            setText(targetText.substring(0, i + 1));
            i++;
            if (i >= targetText.length) {
                clearInterval(intervalId);
                setTimeout(() => {
                    setTypingStep(s => s + 1);
                }, 500);
            }
        }, TYPING_SPEED);

        return () => clearInterval(intervalId);

    }, [typingStep]);

    useEffect(() => {
        if (typingStep === 4) {
            onAnimationComplete();
        }
    }, [typingStep, onAnimationComplete]);

    if (introStep === 'loading') {
        return (
            <div className="flex-1 flex flex-col items-center justify-between p-4 text-center animate-fade-in relative">
                <div className="mb-8 flex flex-col items-center">
                    <LoadingAnimation onComplete={handleLoadingComplete} />
                    {/* Placeholder for layout consistency */}
                    <div className="relative w-56 h-56 mb-6 opacity-0"><NexusOrb /></div>
                    <div className="opacity-0">
                        <h1 className="text-3xl sm:text-4xl font-bold tracking-tight h-[1.2em]">{H1_FULL_TEXT}</h1>
                        <p className="text-xl sm:text-2xl font-semibold mt-4 h-[1.2em]">{P1_FULL_TEXT}</p>
                        <p className="text-base sm:text-lg mt-2 max-w-md h-[1.5em]">{P2_FULL_TEXT}</p>
                    </div>
                </div>
                <div className="w-full max-w-md opacity-0">
                    <ModeTiles onSelectMode={onSelectMode} currentMode={currentMode} selectedModeForAnimation={selectedModeForAnimation} />
                </div>
            </div>
        );
    }

    // For 'content' and 'finished' steps
    const contentAnimationClass = introStep === 'content' ? 'animate-slide-up-fade-in' : 'animate-fade-in';
    const orbAnimationClass = introStep === 'finished' ? 'animate-breathing' : '';

    return (
        <div className={`flex-1 flex flex-col items-center justify-between p-4 text-center relative ${contentAnimationClass}`}>
            <div className="mb-8 flex flex-col items-center">
                <div className="relative w-56 h-56 mb-6">
                    {isFlameVisible && (
                        <div className="absolute inset-0 flex items-center justify-center opacity-[0.12] pointer-events-none">
                            <div className="w-96 h-48 transform scale-[1.75] -rotate-15 -translate-x-6 flame-light-effect">
                                <LogoIcon />
                            </div>
                        </div>
                    )}
                    <div
                        className={`w-full h-full transition-opacity duration-300 relative
                            ${isFlameVisible ? 'opacity-100' : 'opacity-0'}
                            ${igniteFlame ? 'animate-flame-ignite-flash' : ''}
                            ${orbAnimationClass}`
                        }
                    >
                        <NexusOrb />
                    </div>
                    {isFlameVisible && <Embers />}
                </div>

                <div className={`transition-opacity duration-500 ${typingStep > 0 ? 'opacity-100' : 'opacity-0'}`}>
                    <h1 className="text-3xl sm:text-4xl font-bold tracking-tight text-white h-[1.2em]">
                        <span className="bg-gradient-to-r from-orange-500 to-orange-400 bg-clip-text text-transparent">{h1Text.substring(0, 5)}</span>
                        <span className="bg-gradient-to-r from-red-600 to-red-500 bg-clip-text text-transparent">{h1Text.substring(5)}</span>
                        {typingStep === 1 && <span className="blinking-cursor"></span>}
                    </h1>
                    <p className="text-xl sm:text-2xl font-semibold text-white mt-4 h-[1.2em]">
                        {p1Text}
                        {typingStep === 2 && <span className="blinking-cursor"></span>}
                    </p>
                    <p className="text-base sm:text-lg text-[var(--text-secondary)] mt-2 max-w-md h-[1.5em]">
                        {p2Text}
                        {typingStep === 3 && <span className="blinking-cursor"></span>}
                    </p>
                </div>
            </div>

            <div className={`w-full max-w-md ${typingStep === 4 ? 'animate-slide-up-fade-in' : 'opacity-0'}`}>
                <ModeTiles onSelectMode={onSelectMode} currentMode={currentMode} selectedModeForAnimation={selectedModeForAnimation} />
            </div>
        </div>
    );
};

/*
================================================================================
IMPORTANT NOTE FOR PRODUCTION DEPLOYMENT
================================================================================
The Gemini Live API (`ai.live.connect`) is a web-only feature that establishes a
direct WebSocket connection from the client to Google's servers. The Node.js
`@google/genai` SDK does not support this Live API.

This component now securely fetches the API key from the `/api/key` backend
endpoint. This prevents the key from being exposed in the bundled client-side
code, making the feature more secure and stable. The backend server is
responsible for managing the API key.
================================================================================
*/
import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, Blob } from "@google/genai";
